"use server";

import { createClient } from "@/lib/supabase/server";
import { ActionResponse } from "@/types/index";
import { revalidatePath } from "next/cache";
import { logActivity } from "@/lib/audit";
import { createNotification } from "@/lib/notifications";

export type PaymentRecord = {
    id: string;
    amount: number;
    status: string;
    payment_method: string;
    plan: string | null;
    created_at: string;
    tournament_id: string | null;
    provider_id: string | null;
    subscription_expires_at: string | null;
};

export async function getPaymentHistory(): Promise<PaymentRecord[]> {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) return [];

    const { data, error } = await supabase
        .from("payments")
        .select("*")
        .eq("user_id", user.id)
        .order("created_at", { ascending: false });

    if (error) {
        console.error("Error fetching payment history:", error);
        return [];
    }

    return data as PaymentRecord[];
}

export async function recordPayment(data: {
    tournament_id?: string;
    amount: number;
    status: string;
    payment_method: string;
    charge_id?: string;
    plan_type?: string;
}): Promise<ActionResponse> {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) return { success: false, error: "User not authenticated" };

    const insertData: any = {
        user_id: user.id,
        amount: data.amount,
        status: data.status,
        payment_method: data.payment_method,
        provider_id: data.charge_id,
        plan: data.plan_type,
        tournament_id: data.tournament_id
    };

    // Calculate expiration if paying for a subscription
    if ((data.plan_type === 'monthly' || data.plan_type === 'yearly') && data.status === 'success') {
        const now = new Date();
        const expiresAt = new Date(now);

        if (data.plan_type === 'monthly') {
            expiresAt.setMonth(expiresAt.getMonth() + 1);
        } else if (data.plan_type === 'yearly') {
            expiresAt.setFullYear(expiresAt.getFullYear() + 1);
        }

        // Only set if not already set (e.g. by a provider or previous logic)
        if (!insertData.subscription_expires_at) {
            insertData.subscription_expires_at = expiresAt.toISOString();
        }
    }

    const { error } = await supabase.from("payments").insert(insertData);

    if (error) {
        console.error("Error recording payment:", error);
        return { success: false, error: error.message };
    }

    revalidatePath("/organizer/billing");
    revalidatePath("/organizer/dashboard");
    revalidatePath("/");

    // Log and Notify
    await logActivity('PAYMENT_RECORDED', 'payment', data.charge_id || 'manual', { amount: data.amount, status: data.status });
    if (data.status === 'success') {
        await createNotification(user.id, 'payment', 'Payment Successful', `Your payment of ฿${data.amount} was successful.`);
    }

    return { success: true };
}

export async function updateProfilePaymentStatus(_data: {
    payment_status: string;
    payment_id?: string;
    payment_method?: string;
    plan?: string;
}): Promise<ActionResponse> {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) return { success: false, error: "User not authenticated" };

    // The pro status is derived from the 'payments' table history, 
    // so we don't need to duplicate this data in the 'profiles' table 
    // which may not even have these columns.
    return { success: true };
}

"use server";

import { ActionResponse } from "@/types/index";
import { createClient } from "@/lib/supabase/server";

export async function verifySlip(formData: FormData): Promise<ActionResponse<{ amount: number, referenceNo: string, publicUrl: string }>> {
    try {
        const file = formData.get("slip") as File;
        if (!file) {
            return { success: false, error: "No slip file provided" };
        }

        if (file.size > 5 * 1024 * 1024) {
            return { success: false, error: "File size must be less than 5MB" };
        }

        if (!file.type.startsWith("image/")) {
            return { success: false, error: "File must be an image" };
        }

        const supabase = await createClient();

        // Get current user for path organization
        const { data: { user }, error: authError } = await supabase.auth.getUser();
        if (authError || !user) {
            return { success: false, error: "Unauthorized" };
        }

        const referenceNo = `SLIP-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
        const fileExt = file.name.split('.').pop() || 'jpg';
        const fileName = `billing/${user.id}/${referenceNo}.${fileExt}`;

        const { error: uploadError } = await supabase.storage
            .from('slips')
            .upload(fileName, file);

        if (uploadError) {
            console.error("Upload error:", uploadError);
            return { success: false, error: "Failed to upload slip image" };
        }

        const { data: urlData } = supabase.storage
            .from('slips')
            .getPublicUrl(fileName);

        return {
            success: true,
            data: {
                amount: 0, // Admin will verify the amount
                referenceNo: referenceNo,
                publicUrl: urlData.publicUrl
            }
        };

    } catch (error: any) {
        console.error("Slip verification error:", error);
        return {
            success: false,
            error: error?.message || "Failed to verify slip"
        };
    }
}

"use server";

import { createClient } from "@/lib/supabase/server";
import { SupabaseClient } from "@supabase/supabase-js";
import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import { ActionResponse, Match } from "@/types/index";
import { logActivity } from "@/lib/audit";
import { initTournamentStructure } from "@/lib/fixture-utils";
import { validateTournamentAccess } from "@/lib/security";
import { deleteFileFromUrl } from "@/lib/supabase/storage";
import { validateUploadedFile } from "@/lib/file-validation";

export async function addTeam(
    tournamentId: string,
    prevState: unknown,
    formData: FormData
): Promise<ActionResponse> {
    const supabase = await createClient();
    const name = formData.get("name") as string;
    const description = formData.get("description") as string;
    const logoFile = formData.get("logo") as File;
    const logoUrlInput = formData.get("logo_url") as string;

    if (!name) {
        return { success: false, error: "Team name is required" };
    }

    // Security Check: Ensure user is authorized
    const access = await validateTournamentAccess(tournamentId, 'editor');
    if (!access.success) return { success: false, error: access.error };
    const user = access.user;

    // Check global plan
    const { data: globalSubscription } = await supabase
        .from("payments")
        .select("id")
        .eq("user_id", user.id)
        .eq("status", "success")
        .in("plan", ["monthly", "yearly"])
        .is("tournament_id", null)
        .limit(1)
        .single();

    !!globalSubscription;

    // Check Team Limit
    const { data: tourney } = await supabase
        .from("tournaments")
        .select("max_teams")
        .eq("id", tournamentId)
        .single();

    const { count } = await supabase
        .from("tournament_teams")
        .select("*", { count: 'exact', head: true })
        .eq("tournament_id", tournamentId);

    const limit = tourney?.max_teams || 8;
    if (count !== null && count >= limit) {
        return { success: false, error: `Team limit reached (Max ${limit} teams).` };
    }

    let logo_url = logoUrlInput || null;

    // Handle File Upload if URL is not provided
    if (!logo_url && logoFile && logoFile.size > 0) {
        const fileCheck = validateUploadedFile(logoFile);
        if (!fileCheck.valid) return { success: false, error: fileCheck.error };

        const fileExt = logoFile.name.split('.').pop();
        const fileName = `${Date.now()}.${fileExt}`;
        const filePath = `${tournamentId}/${fileName}`;

        const { error: uploadError } = await supabase.storage
            .from('team-logos')
            .upload(filePath, logoFile);

        if (uploadError) {
            console.error("Logo upload failed", uploadError);
            return { success: false, error: `Logo upload failed: ${uploadError.message}` };
        } else {
            const { data: { publicUrl } } = supabase.storage
                .from('team-logos')
                .getPublicUrl(filePath);
            logo_url = publicUrl;
        }
    }

    const { data: teamData, error } = await supabase.from("tournament_teams").insert({
        tournament_id: tournamentId,
        team_id: null, // Manually added teams can link to global teams later if needed
        name,
        description: description || null,
        logo_url,
        created_at: new Date().toISOString(),
    }).select().single();

    if (error) {
        return { success: false, error: error.message };
    }

    // Sync with team_payments for Financial Summary
    if (teamData) {
        // Fetch tournament fee
        const { data: tournament } = await supabase
            .from("tournaments")
            .select("registration_fee")
            .eq("id", tournamentId)
            .single();

        await supabase
            .from("team_payments")
            .upsert({
                tournament_id: tournamentId,
                team_id: teamData.id,
                amount: Number(tournament?.registration_fee || 0),
                status: 'waived',
                paid_at: new Date().toISOString(),
                notes: `Added manually by admin`,
            }, {
                onConflict: 'tournament_id,team_id'
            });
    }

    revalidatePath(`/organizer/tournaments/${tournamentId}`);
    await logActivity('ADD_TEAM', 'tournament', tournamentId, { team_name: name });
    return { success: true };
}

export async function assignTeamGroup(
    teamId: string,
    groupName: string | null,
    tournamentId: string
): Promise<ActionResponse> {
    // Security Check
    const access = await validateTournamentAccess(tournamentId, 'editor');
    if (!access.success) return { success: false, error: access.error };

    const supabase = await createClient();
    const { error } = await supabase
        .from("tournament_teams")
        .update({ group_name: groupName })
        .eq("id", teamId);

    if (error) {
        return { success: false, error: error.message };
    }

    revalidatePath(`/organizer/tournaments/${tournamentId}`);
    return { success: true };
}

