import Image from "next/image";
import { Search, Plus, User, MoreHorizontal, Calendar, Shield } from "lucide-react";
import { createGlobalPlayer } from "@/app/[locale]/admin/actions";
import { toast } from "sonner";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";

interface AdminPlayersTableProps {
    initialPlayers: any[];
}

export function AdminPlayersTable({ initialPlayers }: AdminPlayersTableProps) {
    const t = useTranslations("Admin");
    const commonT = useTranslations("Common");
    const [searchTerm, setSearchTerm] = useState("");
    const [players, setPlayers] = useState(initialPlayers);
    const [isAddDialogOpen, setIsAddDialogOpen] = useState(false);
    const [newPlayerName, setNewPlayerName] = useState("");
    const [newPlayerPhoto, setNewPlayerPhoto] = useState("");
    const [newPlayerDOB, setNewPlayerDOB] = useState("");

    const filteredPlayers = players.filter(player =>
        (player.name?.toLowerCase() || "").includes(searchTerm.toLowerCase())
    );

    const handleAddPlayer = async () => {
        if (!newPlayerName.trim()) {
            toast.error("Player name is required");
            return;
        }

        const result = await createGlobalPlayer(newPlayerName, {
            photo_url: newPlayerPhoto,
            date_of_birth: newPlayerDOB || null
        });

        if (result.success) {
            toast.success("Player added successfully");
            setNewPlayerName("");
            setNewPlayerPhoto("");
            setNewPlayerDOB("");
            setIsAddDialogOpen(false);
            window.location.reload();
        } else {
            toast.error(result.error || "Failed to add player");
        }
    };

    return (
        <div className="space-y-4">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="relative w-full md:w-[300px]">
                    <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                    <Input
                        placeholder={t("search_players")}
                        className="pl-8"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>

                <Dialog open={isAddDialogOpen} onOpenChange={setIsAddDialogOpen}>
                    <DialogTrigger asChild>
                        <Button className="text-[10px] font-black tracking-wider h-10 px-6">
                            <Plus className="mr-2 h-4 w-4" />
                            {t("add_player")}
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="sm:max-w-[500px] border-border p-0 overflow-hidden">
                        <div className="bg-secondary/10 px-6 py-5 border-b border-border relative">
                            <div className="absolute top-0 left-0 w-1 h-full bg-secondary" />
                            <DialogHeader>
                                <DialogTitle className="text-xl font-black italic tracking-tighter text-foreground flex items-center gap-2">
                                    <Shield className="h-5 w-5 text-secondary" />
                                    {t("add_player")}
                                </DialogTitle>
                                <DialogDescription className="text-muted-foreground text-sm font-medium pt-1">
                                    Create a new player record in the global database.
                                </DialogDescription>
                            </DialogHeader>
                        </div>

                        <div className="px-6 py-6 space-y-4">
                            <div className="grid gap-2">
                                <Label htmlFor="name" className="text-[10px] font-black tracking-wider">
                                    {t("player_name")}
                                </Label>
                                <Input
                                    id="name"
                                    value={newPlayerName}
                                    onChange={(e) => setNewPlayerName(e.target.value)}
                                    placeholder={t("player_name_placeholder")}
                                    className="border-muted-foreground/20 focus:border-secondary focus:ring-secondary/20"
                                />
                            </div>
                            <div className="grid gap-2">
                                <Label htmlFor="photo" className="text-[10px] font-black tracking-wider">
                                    {t("photo_url")}
                                </Label>
                                <Input
                                    id="photo"
                                    value={newPlayerPhoto}
                                    onChange={(e) => setNewPlayerPhoto(e.target.value)}
                                    placeholder="https://..."
                                    className="border-muted-foreground/20 focus:border-secondary focus:ring-secondary/20"
                                />
                            </div>
                            <div className="grid gap-2">
                                <Label htmlFor="dob" className="text-[10px] font-black tracking-wider">
                                    {t("date_of_birth")}
                                </Label>
                                <Input
                                    id="dob"
                                    type="date"
                                    value={newPlayerDOB}
                                    onChange={(e) => setNewPlayerDOB(e.target.value)}
                                    className="border-muted-foreground/20 focus:border-secondary focus:ring-secondary/20"
                                />
                            </div>
                        </div>

                        <DialogFooter className="px-6 py-4 border-t border-border bg-muted/30">
                            <Button 
                                variant="outline" 
                                onClick={() => setIsAddDialogOpen(false)}
                                className="text-[10px] font-black tracking-wider"
                            >
                                {commonT("cancel")}
                            </Button>
                            <Button 
                                onClick={handleAddPlayer}
                                className="text-[10px] font-black tracking-wider"
                            >
                                {t("add_player")}
                            </Button>
                        </DialogFooter>
                    </DialogContent>
                </Dialog>
            </div>

            <div className="border border-border bg-card overflow-hidden">
                <Table>
                    <TableHeader>
                        <TableRow className="border-b border-border bg-muted/30 hover:bg-muted/30">
                            <TableHead className="text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">
                                {commonT("user")}
                            </TableHead>
                            <TableHead className="text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">
                                {t("date_of_birth")}
                            </TableHead>
                            <TableHead className="text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">
                                {t("created_at")}
                            </TableHead>
                            <TableHead className="text-right text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">
                                {t("actions")}
                            </TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {filteredPlayers.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={4} className="h-24 text-center text-muted-foreground">
                                    {t("no_results")}
                                </TableCell>
                            </TableRow>
                        ) : (
                            filteredPlayers.map((player) => (
                                <TableRow key={player.id} className="border-b border-border/50 hover:bg-muted/10 transition-colors">
                                    <TableCell>
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 bg-muted/50 flex items-center justify-center border border-border overflow-hidden shrink-0">
                                                {player.photo_url ? (
                                                    <Image src={player.photo_url} alt={player.name} width={40} height={40} className="w-full h-full object-cover" unoptimized />
                                                ) : (
                                                    <User className="h-5 w-5 text-muted-foreground" />
                                                )}
                                            </div>
                                            <div className="flex flex-col">
                                                <span className="font-bold text-sm tracking-tight">{player.name}</span>
                                                <span className="text-[10px] font-medium text-muted-foreground tracking-wider -mt-0.5">PLAYER</span>
                                            </div>
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex items-center gap-2 text-xs font-medium">
                                            <Calendar className="h-3 w-3 text-muted-foreground" />
                                            {player.date_of_birth || "-"}
                                        </div>
                                    </TableCell>
                                    <TableCell className="text-muted-foreground text-[10px] font-bold tracking-tight">
                                        {player.created_at ? new Date(player.created_at).toLocaleDateString() : "-"}
                                    </TableCell>
                                    <TableCell className="text-right">
                                        <Button variant="ghost" size="icon" className="h-8 w-8 hover:bg-muted/30">
                                            <MoreHorizontal className="h-4 w-4" />
                                        </Button>
                                    </TableCell>
                                </TableRow>
                            ))
                        )}
                    </TableBody>
                </Table>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useTranslations } from "next-intl";
import { formatDate } from "@/lib/date";
import { useLocale } from "next-intl";
import { Search, Trophy, Trash2, ExternalLink } from "lucide-react";
import { deleteTournamentAsAdmin } from "@/app/[locale]/admin/actions";
import { Link } from "@/i18n/routing";

import { useToast } from "@/hooks/use-toast";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger,
} from "@/components/ui/alert-dialog";

interface AdminTournamentsTableProps {
    initialTournaments: any[];
}

export function AdminTournamentsTable({ initialTournaments }: AdminTournamentsTableProps) {
    const t = useTranslations("Admin");
    const tCommon = useTranslations("Common");
    const tSettings = useTranslations("Settings");
    const locale = useLocale();
    const { toast } = useToast();
    const [searchTerm, setSearchTerm] = useState("");
    const [page, setPage] = useState(1);
    const itemsPerPage = 100;
    const [tournaments, setTournaments] = useState(initialTournaments);

    const filteredTournaments = tournaments.filter(t =>
        (t.name?.toLowerCase() || "").includes(searchTerm.toLowerCase()) ||
        (t.owner_email?.toLowerCase() || "").includes(searchTerm.toLowerCase())
    );

    const paginatedTournaments = filteredTournaments.slice((page - 1) * itemsPerPage, page * itemsPerPage);
    const totalPages = Math.ceil(filteredTournaments.length / itemsPerPage) || 1;

    const handleDelete = async (id: string, name: string) => {
        const result = await deleteTournamentAsAdmin(id);
        if (result.success) {
            toast({
                description: `${tCommon("delete")}: ${name}`,
            });
            setTournaments(tournaments.filter(t => t.id !== id));
        } else {
            toast({
                variant: "destructive",
                description: `${tCommon("error")}: ${result.error}`,
            });
        }
    };

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'active': return 'default';
            case 'completed': return 'secondary';
            default: return 'outline';
        }
    };

    return (
        <div className="space-y-4">
            <div className="relative w-full md:w-[300px]">
                <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                <Input
                    placeholder={t("search_tournaments")}
                    className="pl-8"
                    value={searchTerm}
                    onChange={(e) => {
                        setSearchTerm(e.target.value);
                        setPage(1);
                    }}
                />
            </div>

            <div className="border border-border bg-card overflow-hidden">
                <Table>
                    <TableHeader>
                        <TableRow className="border-b border-border bg-muted/30 hover:bg-muted/30">
                            <TableHead className="text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">{t("tournaments")}</TableHead>
                            <TableHead className="text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">{t("owner")}</TableHead>
                            <TableHead className="text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">{t("status")}</TableHead>
                            <TableHead className="text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">{t("created_at")}</TableHead>
                            <TableHead className="text-right text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">{t("actions")}</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {filteredTournaments.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={5} className="h-24 text-center text-muted-foreground">
                                    {t("no_results")}
                                </TableCell>
                            </TableRow>
                        ) : (
                            paginatedTournaments.map((tournament) => (
                                <TableRow key={tournament.id} className="border-b border-border/50 hover:bg-muted/10 transition-colors">
                                    <TableCell>
                                        <div className="flex items-center gap-3">
                                            <div className="h-8 w-8 bg-secondary/10 flex items-center justify-center border border-secondary/20 shrink-0">
                                                <Trophy className="h-4 w-4 text-secondary" />
                                            </div>
                                            <div className="flex flex-col min-w-0">
                                                <span className="font-bold text-sm truncate">{tournament.name}</span>
                                                <span className="text-[10px] text-muted-foreground tracking-wider font-medium">{tournament.format}</span>
                                            </div>
                                        </div>
                                    </TableCell>
                                    <TableCell className="text-sm text-muted-foreground">
                                        {tournament.owner_email}
                                    </TableCell>
                                    <TableCell>
                                        <Badge
                                            variant={getStatusColor(tournament.status)}
                                            className="text-[10px] font-black"
                                        >
                                            {tournament.status}
                                        </Badge>
                                    </TableCell>
                                    <TableCell className="text-xs text-muted-foreground">
                                        {formatDate(tournament.created_at, "d MMM yyyy", locale)}
                                    </TableCell>
                                    <TableCell className="text-right">
                                        <div className="flex justify-end gap-1">
                                            <Link href={`/organizer/tournaments/${tournament.id}`} target="_blank">
                                                <Button variant="ghost" size="icon" title={tCommon("manage")} className="hover:bg-muted/30">
                                                    <ExternalLink className="h-4 w-4 text-muted-foreground" />
                                                </Button>
                                            </Link>

                                            <AlertDialog>
                                                <AlertDialogTrigger asChild>
                                                    <Button variant="ghost" size="icon" title={tCommon("delete")} className="hover:bg-destructive/10">
                                                        <Trash2 className="h-4 w-4 text-destructive" />
                                                    </Button>
                                                </AlertDialogTrigger>
                                                <AlertDialogContent className="border-border">
                                                    <AlertDialogHeader>
                                                        <AlertDialogTitle className="font-black italic tracking-tighter">
                                                            {tSettings("delete_tournament")}?
                                                        </AlertDialogTitle>
                                                        <AlertDialogDescription>
                                                            {tSettings("delete_desc")}. {t("deletions_removals")} <b>{tournament.name}</b>.
                                                        </AlertDialogDescription>
                                                    </AlertDialogHeader>
                                                    <AlertDialogFooter>
                                                        <AlertDialogCancel className="text-[10px] font-black">
                                                            {tCommon("cancel")}
                                                        </AlertDialogCancel>
                                                        <AlertDialogAction
                                                            className="bg-destructive text-destructive-foreground hover:bg-destructive/90 text-[10px] font-black"
                                                            onClick={() => handleDelete(tournament.id, tournament.name)}
                                                        >
                                                            {tCommon("delete")}
                                                        </AlertDialogAction>
                                                    </AlertDialogFooter>
                                                </AlertDialogContent>
                                            </AlertDialog>
                                        </div>
                                    </TableCell>
                                </TableRow>
                            ))
                        )}
                    </TableBody>
                </Table>
            </div>
            {filteredTournaments.length > 0 && (
                <div className="flex items-center justify-between py-2">
                    <div className="text-[10px] tracking-wider font-bold text-muted-foreground hidden sm:block">
                        Showing {(page - 1) * itemsPerPage + 1} to {Math.min(page * itemsPerPage, filteredTournaments.length)} of {filteredTournaments.length} entries
                    </div>
                    <div className="flex items-center space-x-2">
                        <Button
                            variant="outline"
                            size="sm"
                            className="text-[10px] font-black"
                            onClick={() => setPage(p => Math.max(1, p - 1))}
                            disabled={page === 1}
                        >
                            Previous
                        </Button>
                        <span className="text-[10px] tracking-wider font-bold text-muted-foreground px-2">Page {page} of {totalPages}</span>
                        <Button
                            variant="outline"
                            size="sm"
                            className="text-[10px] font-black"
                            onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                            disabled={page === totalPages}
                        >
                            Next
                        </Button>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { useState } from "react";
import { useTranslations } from "next-intl";
import { formatDate } from "@/lib/date";
import { useLocale } from "next-intl";
import { Search, Shield, User, MoreHorizontal, Check } from "lucide-react";
import { updateUserRole } from "@/app/[locale]/admin/actions";
import { toast } from "sonner";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

interface AdminUsersTableProps {
    initialUsers: any[];
}

export function AdminUsersTable({ initialUsers }: AdminUsersTableProps) {
    const t = useTranslations("Admin");
    const tCommon = useTranslations("Common");
    const locale = useLocale();
    const [searchTerm, setSearchTerm] = useState("");
    const [page, setPage] = useState(1);
    const itemsPerPage = 100;
    const [users, setUsers] = useState(initialUsers);

    const filteredUsers = users.filter(user =>
        (user.email?.toLowerCase() || "").includes(searchTerm.toLowerCase()) ||
        (user.full_name?.toLowerCase() || "").includes(searchTerm.toLowerCase())
    );

    const paginatedUsers = filteredUsers.slice((page - 1) * itemsPerPage, page * itemsPerPage);
    const totalPages = Math.ceil(filteredUsers.length / itemsPerPage) || 1;

    const handleRoleChange = async (userId: string, newRole: string) => {
        const result = await updateUserRole(userId, newRole);
        if (result.success) {
            toast.success(t("role_updated"));
            setUsers(users.map(u => u.id === userId ? { ...u, role: newRole } : u));
        } else {
            toast.error(t("role_update_failed"));
        }
    };

    return (
        <div className="space-y-4">
            <div className="relative w-full md:w-[300px]">
                <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                <Input
                    placeholder={t("search_users")}
                    className="pl-8"
                    value={searchTerm}
                    onChange={(e) => {
                        setSearchTerm(e.target.value);
                        setPage(1);
                    }}
                />
            </div>

            <div className="border border-border bg-card overflow-hidden">
                <Table>
                    <TableHeader>
                        <TableRow className="border-b border-border bg-muted/30 hover:bg-muted/30">
                            <TableHead className="text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">{t("user")}</TableHead>
                            <TableHead className="text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">{t("role")}</TableHead>
                            <TableHead className="text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">{t("created_at")}</TableHead>
                            <TableHead className="text-right text-[10px] font-black italic tracking-[0.15em] text-muted-foreground">{t("actions")}</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {filteredUsers.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={4} className="h-24 text-center text-muted-foreground">
                                    {t("no_results")}
                                </TableCell>
                            </TableRow>
                        ) : (
                            paginatedUsers.map((user) => (
                                <TableRow key={user.id} className="border-b border-border/50 hover:bg-muted/10 transition-colors">
                                    <TableCell>
                                        <div className="flex items-center gap-3">
                                            <div className="h-8 w-8 bg-secondary/10 flex items-center justify-center border border-secondary/20 shrink-0">
                                                <User className="h-4 w-4 text-secondary" />
                                            </div>
                                            <div className="flex flex-col min-w-0">
                                                <span className="font-bold text-sm truncate">{user.email}</span>
                                                <span className="text-[10px] text-muted-foreground tracking-wider font-medium">{user.full_name || t("no_name")}</span>
                                            </div>
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <Badge
                                            variant={user.role === 'admin' ? 'default' : 'outline'}
                                            className="text-[10px] font-black"
                                        >
                                            {user.role === 'admin' && <Shield className="mr-1 h-3 w-3" />}
                                            {user.role}
                                        </Badge>
                                    </TableCell>
                                    <TableCell className="text-xs text-muted-foreground">
                                        {user.created_at
                                            ? formatDate(user.created_at, "d MMM yyyy", locale)
                                            : "-"}
                                    </TableCell>
                                    <TableCell className="text-right">
                                        <DropdownMenu>
                                            <DropdownMenuTrigger asChild>
                                                <Button variant="ghost" className="h-8 w-8 p-0 hover:bg-muted/30">
                                                    <span className="sr-only">{t("actions")}</span>
                                                    <MoreHorizontal className="h-4 w-4" />
                                                </Button>
                                            </DropdownMenuTrigger>
                                            <DropdownMenuContent align="end" className="border-border">
                                                <DropdownMenuLabel className="text-[10px] font-black tracking-wider">{t("actions")}</DropdownMenuLabel>
                                                <DropdownMenuItem onClick={() => navigator.clipboard.writeText(user.id)}>
                                                    {t("copy_user_id")}
                                                </DropdownMenuItem>
                                                <DropdownMenuSeparator />
                                                <DropdownMenuLabel className="text-[10px] font-black tracking-wider">{t("change_role")}</DropdownMenuLabel>
                                                <DropdownMenuItem onClick={() => handleRoleChange(user.id, 'user')}>
                                                    <User className="mr-2 h-4 w-4" />
                                                    {t("set_as_user")}
                                                    {user.role === 'user' && <Check className="ml-auto h-4 w-4 text-secondary" />}
                                                </DropdownMenuItem>
                                                <DropdownMenuItem onClick={() => handleRoleChange(user.id, 'admin')}>
                                                    <Shield className="mr-2 h-4 w-4" />
                                                    {t("set_as_admin")}
                                                    {user.role === 'admin' && <Check className="ml-auto h-4 w-4 text-secondary" />}
                                                </DropdownMenuItem>
                                            </DropdownMenuContent>
                                        </DropdownMenu>
                                    </TableCell>
                                </TableRow>
                            ))
                        )}
                    </TableBody>
                </Table>
            </div>
            {filteredUsers.length > 0 && (
                <div className="flex items-center justify-between py-2">
                    <div className="text-[10px] tracking-wider font-bold text-muted-foreground hidden sm:block">
                        Showing {(page - 1) * itemsPerPage + 1} to {Math.min(page * itemsPerPage, filteredUsers.length)} of {filteredUsers.length} entries
                    </div>
                    <div className="flex items-center space-x-2">
                        <Button
                            id="pagination-prev"
                            variant="outline"
                            size="sm"
                            className="text-[10px] font-black"
                            onClick={() => {
                                setPage(p => Math.max(1, p - 1));
                                window.scrollTo({ top: 0, behavior: 'smooth' });
                            }}
                            disabled={page === 1}
                        >
                            Previous
                        </Button>
                        <span className="text-[10px] tracking-wider font-bold text-muted-foreground px-2" id="pagination-info">
                            Page {page} of {totalPages}
                        </span>
                        <Button
                            id="pagination-next"
                            variant="outline"
                            size="sm"
                            className="text-[10px] font-black"
                            onClick={() => {
                                setPage(p => Math.min(totalPages, p + 1));
                                window.scrollTo({ top: 0, behavior: 'smooth' });
                            }}
                            disabled={page === totalPages}
                        >
                            Next
                        </Button>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { useState } from "react";
