                                                    </div>
                                                    <div>
                                                        <p className="text-[10px] font-bold text-muted-foreground/40 leading-none mb-1">
                                                            PromptPay ID
                                                        </p>
                                                        <p className="text-sm font-mono font-bold text-foreground">
                                                            {promptPayId}
                                                        </p>
                                                    </div>
                                                </div>
                                                <div className="text-secondary opacity-0 group-hover:opacity-100 transition-opacity">
                                                    {copied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
                                                </div>
                                            </button>
                                        </div>

                                        <div className="space-y-4">
                                            <p className="text-[10px] text-center font-black italic tracking-widest text-muted-foreground/60 leading-relaxed px-2">
                                                {t("paid_instruction", { defaultValue: "Please scan the QR code to pay, then upload your transfer slip to complete." })}
                                            </p>
                                            
                                            <div className="relative">
                                                <Input
                                                    type="file"
                                                    accept="image/*"
                                                    onChange={handleUploadSlip}
                                                    disabled={isUploadingSlip}
                                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-20"
                                                />
                                                <Button 
                                                    className="w-full relative h-12 font-black italic italic tracking-widest bg-secondary hover:bg-secondary/90 shadow-[0_4px_14px_rgba(var(--secondary),0.3)] transition-all hover:scale-[1.02] active:scale-[0.98]" 
