                                                        <><UploadCloud className="w-4 h-4 mr-2" /> {t("upload_slip", { defaultValue: "Upload Payment Slip" })}</>
                                                    )}
                                                </Button>
                                            </div>
                                        </div>
                                    </div>
                                </>
                            )}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import { CreateTournamentDialog } from "@/components/tournaments/create-tournament-dialog";
import { CreateTeamDialog } from "@/components/dashboard/create-team-dialog";
import { Trophy, Users } from "lucide-react";
import { useTranslations } from "next-intl";

interface EmptyStateProps {
    isPro: boolean;
    type?: 'tournament' | 'team';
    tournaments?: { id: string; name: string }[];
}

export function EmptyState({ isPro, type = 'tournament', tournaments = [] }: EmptyStateProps) {
    const t = useTranslations("Common");
    const tTeam = useTranslations("Team");

    const isTeam = type === 'team';
    const Icon = isTeam ? Users : Trophy;
    
    // Using specific translations for the personal dashboard view
    const title = isTeam ? tTeam("no_teams_yet") : t("no_tournaments");
    const description = isTeam ? tTeam("my_teams_desc") : t("no_tournaments_desc");

    return (
        <div className="flex min-h-[400px] flex-col items-center justify-center border border-border bg-muted/5 p-8 text-center animate-in fade-in-50 relative overflow-hidden group">
            <div className="absolute top-0 left-0 w-1 h-full bg-muted group-hover:bg-secondary/40 transition-colors" />
            
            <div className="p-8 bg-background border border-border rotate-12 transition-transform group-hover:rotate-0 shadow-xl mb-6 relative z-10">
                <Icon className="h-12 w-12 text-muted-foreground opacity-30 -rotate-12 group-hover:rotate-0 transition-transform" />
            </div>

            <h3 className="text-2xl font-black italic tracking-tight mb-2 relative z-10">
                {title}
            </h3>
            <p className="text-[11px] font-bold text-muted-foreground/60 max-w-sm mb-8 flex items-center gap-2 relative z-10">
                <span className="w-4 h-[1px] bg-muted-foreground/30" />
                {description}
                <span className="w-4 h-[1px] bg-muted-foreground/30" />
            </p>
            <div className="relative z-10">
                {isTeam ? (
                    <CreateTeamDialog />
                ) : (
                    <CreateTournamentDialog isPro={isPro} />
                )}
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useTranslations } from "next-intl";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardTitle } from "@/components/ui/card";
import { updateProfile } from "@/actions/common/user";
import { Loader2, User } from "lucide-react";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";

export function ProfileForm({ user }: { user: any }) {
    const t = useTranslations("Profile");
    const tCommon = useTranslations("Common");
    const [isLoading, setIsLoading] = useState(false);
    const { toast } = useToast();

    async function handleUpdate(formData: FormData) {
        setIsLoading(true);
        const result = await updateProfile(formData);
        setIsLoading(false);

        if (result?.error) {
            toast({
                title: t("error"),
                description: result.error,
                variant: "destructive",
            });
        } else {
            toast({
                title: t("success"),
                description: t("updated_successfully"),
            });
        }
    }

    return (
        <div className="space-y-4 md:space-y-6">
            <div className="flex items-center gap-3 mb-4 md:mb-6">
                <User className="h-5 w-5 text-secondary" />
                <h3 className="text-xl font-black italic tracking-tighter text-foreground">
                    {t("user_info")}
                </h3>
            </div>
            
            <div className="bg-background border relative overflow-hidden group hover:bg-muted/5 transition-colors p-4 md:p-6 shadow-sm">
                <div className="absolute top-0 left-0 w-1 h-full bg-muted group-hover:bg-secondary/40 transition-colors" />
                
                <form action={handleUpdate} className="grid gap-4 md:gap-6">
                    <div className="grid gap-3">
                        <Label htmlFor="email" className="text-[10px] font-black italic tracking-widest text-secondary/70">
                            {t("email")}
                        </Label>
                        <Input 
                            id="email" 
                            value={user?.email} 
                            disabled 
                            className="bg-muted/10 border-border text-muted-foreground/40 cursor-not-allowed italic font-medium h-12" 
                        />
                    </div>
                    <div className="grid gap-3">
                        <Label htmlFor="fullName" className="text-[10px] font-black italic tracking-widest text-secondary/70">
                            {t("full_name")}
                        </Label>
                        <Input
                            id="fullName"
                            name="fullName"
                            defaultValue={user?.user_metadata?.full_name || ""}
                            placeholder={t("enter_full_name")}
                            className="bg-muted/20 border-border text-foreground h-12 focus-visible:ring-secondary/30"
                        />
                    </div>
                    <div className="flex justify-start">
                        <Button type="submit" disabled={isLoading} variant="secondary" className="h-12 px-10 font-black italic tracking-tighter shadow-[0_0_20px_rgba(0,196,154,0.1)] hover:shadow-[0_0_30px_rgba(0,196,154,0.2)] transition-all">
                            {isLoading ? (
                                <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                            ) : (
                                <span className="flex items-center gap-2">
                                    {tCommon("save")}
                                </span>
                            )}
                        </Button>
                    </div>
                </form>
            </div>
        </div>
    );
}

'use client'

import { Match, Player, MatchEvent } from "@/types";
import { EVENT_TYPES } from "./constants";
import { Trash2, Clock } from "lucide-react";
// Removed unused Card, CardContent imports
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { useTranslations } from "next-intl";

interface EventTimelineProps {
    events: MatchEvent[];
    match: Match;
    readOnly?: boolean;
    onDelete?: (eventId: string) => void;
}

export function EventTimeline({ events, match, readOnly = false, onDelete }: EventTimelineProps) {
    const t = useTranslations("Console");

    return (
        <div className="bg-foreground/5 border border-foreground/5 relative overflow-hidden group">
            {/* Background Decorative Element */}
            <div className="absolute top-0 right-0 w-24 h-24 bg-foreground/5 rotate-12 translate-x-4 -translate-y-4 pointer-events-none" />
            
            <div className="px-4 pt-2 md:px-6 md:pt-6 flex items-center justify-between px-4 relative z-10">
                <div className="space-y-1">
                    <h3 className="text-[10px] font-black tracking-widest text-secondary">{t("match_log") || "Match Log"}</h3>
                    <p className="text-[8px] text-muted-foreground italic">CHRONOLOGICAL EVENT HISTORY</p>
                </div>
            </div>

            <div className="px-4 md:px-6 my-2 md:my-3">
                <div className="border-t border-foreground/5"/>
            </div>

            <div className="relative z-10">
                <div className="max-h-[500px] overflow-y-auto px-4 pb-4 md:px-6 md:pb-6 space-y-2 md:space-y-3 no-scrollbar scroll-smooth">
                    {events.length === 0 ? (
                        <div className="flex flex-col items-center justify-center py-16 opacity-20">
                            <Clock className="w-10 h-10 mb-4 text-foreground" />
                            <p className="text-[10px] font-black tracking-widest text-foreground">{t("no_events")}</p>
                        </div>
                    ) : (
                        events.map((event) => {
                            const evtConfig = EVENT_TYPES.find(e => e.type === event.event_type);
                            const isNeutral = !event.team_id;
                            const isHome = !isNeutral && event.team_id === match.home_team_id;
                            const accentColor = isNeutral ? 'bg-foreground/20' :
                                             event.event_type === 'red_card' ? 'bg-red-500' : 
                                             event.event_type === 'yellow_card' ? 'bg-yellow-400' : 
                                             'bg-secondary';
                            
                            return (
                                <div 
                                    key={event.id} 
                                    className={cn(
                                        "relative flex items-center gap-2 md:gap-3 group/item w-full",
                                        isNeutral ? "flex-row justify-center" : (isHome ? "flex-row" : "flex-row-reverse")
                                    )}
                                >
                                    {/* Minute Indicator (Hidden for neutral events) */}
                                    {!isNeutral && (
                                        <div className="w-6 flex flex-col items-center">
                                            <span className={cn(
                                                "text-sm font-black italic tracking-tighter drop-shadow-sm transition-colors",
                                                isHome ? "text-foreground/40 group-hover/item:text-secondary" : "text-foreground/40 group-hover/item:text-foreground"
                                            )}>
                                                {event.minute}&apos;
                                            </span>
                                        </div>
                                    )}

                                    <div className={cn(
                                        "flex-1 min-w-0 transition-all relative",
                                        isNeutral ? "py-2" : "p-2 md:p-3 bg-foreground/5 border border-foreground/5 group-hover/item:bg-foreground/10 group-hover/item:border-foreground/10",
                                        !isNeutral && (isHome ? "text-left" : "text-right")
                                    )}>
                                        {/* Status Accent Bar (Only for team events) */}
                                        {!isNeutral && <div className={cn("absolute top-0 w-[2px] h-full", accentColor, isHome ? "left-0" : "right-0")} />}
                                        
                                        <div className={cn(
                                            "flex items-center justify-between gap-4",
                                            isNeutral ? "flex-row" : (isHome ? "flex-row" : "flex-row-reverse")
                                        )}>
                                            {isNeutral ? (
                                                <div className="flex items-center gap-4 w-full">
                                                    <div className="flex-1 h-[1px] bg-secondary/40" />
                                                    <div className="flex flex-col items-center">
                                                        <span className="text-[10px] font-black tracking-[0.3em] italic text-secondary drop-shadow-md">
                                                            {t(evtConfig?.label || event.event_type)}
                                                        </span>
                                                        <div className="flex items-center gap-2">
                                                            <span className="text-sm font-black italic text-foreground/40">
                                                                {event.minute}&apos;
                                                            </span>
                                                            {event.extra_info?.added_minutes && (
                                                                <span className="text-sm1 font-black italic text-foreground/40">
                                                                    (+{event.extra_info.added_minutes} MIN)
                                                                </span>
                                                            )}
                                                        </div>
                                                    </div>
                                                    <div className="flex-1 h-[1px] bg-secondary/40" />
                                                </div>
                                            ) : (
                                                <div className="min-w-0">
                                                    <div className={cn(
                                                        "flex items-center gap-2 mb-1",
                                                        isNeutral ? "justify-center" : (isHome ? "flex-row" : "flex-row-reverse")
                                                    )}>
                                                        <span className={cn(
                                                            "text-[9px] font-black tracking-widest italic",
                                                            event.event_type === 'goal' ? "text-secondary" : (isNeutral ? "text-foreground/60" : "text-foreground/40")
                                                        )}>
                                                            {event.event_type === 'penalty_shot' 
                                                                ? (event.extra_info?.scored ? t("penalty_scored") : t("penalty_missed"))
                                                                : t(evtConfig?.label || event.event_type)}
                                                        </span>
                                                        {!isNeutral && (
                                                            <>
                                                                <span className="text-[10px] text-foreground/20">•</span>
                                                                <span className="text-[10px] font-black italic tracking-tighter text-foreground truncate max-w-[120px]">
                                                                    {isHome ? match.home_team?.name : match.away_team?.name}
                                                                </span>
                                                            </>
                                                        )}
                                                    </div>
                                                    <p className={cn(
                                                        "text-xs font-black italic tracking-widest text-foreground truncate",
                                                        isNeutral ? "text-center" : ""
                                                    )}>
                                                        {event.player_name || "Match Event"}
                                                    </p>
                                                    {event.extra_info?.reason && (
                                                        <p className="text-[9px] text-foreground/40 italic mt-1 font-medium">{event.extra_info.reason}</p>
                                                    )}
                                                </div>
                                            )}
                                            
                                            {!readOnly && onDelete && (
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    className="h-8 w-8 text-foreground/20 hover:text-red-500 hover:bg-red-500/10 opacity-100 md:opacity-0 group-hover/item:opacity-100 transition-all shrink-0"
                                                    onClick={() => onDelete(event.id)}
                                                >
                                                    <Trash2 className="h-3 w-3" />
                                                </Button>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            );
                        })
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { EVENT_TYPES } from "./constants";
import { EventType, Player, MatchEvent } from "@/types";
import { cn } from "@/lib/utils";
import { useTranslations } from "next-intl";

interface MatchEventDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    teamId: string;
    eventType: EventType | null;
    initialMinute: number;
    players: Player[]; // Players of the selected team
    allPlayers?: Player[]; // All players (for assist usually, though custom requires team specific)
    existingEvents: MatchEvent[]; // To check for previous cards
    onSave: (data: { minute: number; playerId: string; extraInfo: any; autoRed?: boolean }) => void;
}

export function MatchEventDialog({
    open,
    onOpenChange,
    teamId,
    eventType,
    initialMinute,
    players,
    existingEvents,
    onSave
}: MatchEventDialogProps) {
    const t = useTranslations("Console");
    const tCommon = useTranslations("Common");

    const [minute, setMinute] = useState<string>("");
    const [playerId, setPlayerId] = useState<string>("");
    const [assistPlayerId, setAssistPlayerId] = useState<string>("");
    const [subInPlayerId, setSubInPlayerId] = useState<string>("");

    useEffect(() => {
        if (open) {
            const timer = setTimeout(() => {
                setMinute(initialMinute.toString());
                setPlayerId("");
                setAssistPlayerId("");
                setSubInPlayerId("");
            }, 0);
            return () => clearTimeout(timer);
        }
    }, [open, initialMinute, eventType]);

    const handleSave = () => {
        const min = parseInt(minute) || 0;
        const extraInfo: any = {};
        let autoRed = false;

        // Card Ban Logic: Check if player already has a yellow card
        if (eventType === 'yellow_card' && playerId && playerId !== 'unknown') {
            const previousYellows = existingEvents.filter(e =>
                e.player_id === playerId &&
                e.event_type === 'yellow_card'
            );

            if (previousYellows.length >= 1) {
                if (!confirm(t("second_yellow_warning") || "Player already has a yellow card. This will be recorded as a Second Yellow (Red Card). Proceed?")) {
                    return;
                }
                autoRed = true;
                extraInfo.is_second_yellow = true;
            }
        }

        if (eventType === 'goal' && assistPlayerId && assistPlayerId !== 'none') {
            extraInfo.assist_player_id = assistPlayerId;
        }
        if (eventType === 'substitution') {
            extraInfo.out_player_id = playerId;
            extraInfo.in_player_id = subInPlayerId;
        }

        onSave({
            minute: min,
            playerId,
            extraInfo,
            autoRed
        });
        onOpenChange(false);
    };

    if (!eventType) return null;

    const eventConfig = EVENT_TYPES.find(t => t.type === eventType);
    const Icon = eventConfig?.icon;

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="bg-card border-foreground/5 p-0 overflow-hidden max-w-md">
                {/* Header Decoration */}
                <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-secondary/50 via-secondary to-secondary/50" />
                
                <DialogHeader className="p-8 pb-4">
                    <DialogTitle className="flex items-center gap-4 text-2xl font-black italic tracking-tighter text-foreground">
                        <div className={cn("p-2 bg-foreground/5 border border-foreground/10", eventConfig?.color)}>
                            {Icon && <Icon className="h-6 w-6" />}
                        </div>
                        {eventConfig?.label && t(eventConfig.label)}
                    </DialogTitle>
                    <p className="text-[10px] font-black tracking-[0.2em] text-muted-foreground/40 mt-2 italic">CONFIGURE MATCH EVENT DATA</p>
                </DialogHeader>

                <div className="px-8 py-6 space-y-8 relative">
                    {/* Background Decorative Element */}
                    <div className="absolute top-0 right-0 w-32 h-32 bg-secondary/5 -rotate-12 translate-x-12 -translate-y-12 pointer-events-none" />

                    {/* Time Input */}
                    <div className="space-y-3 relative z-10">
                        <Label className="text-[10px] font-black tracking-widest text-secondary italic">{t("time")}</Label>
                        <Input
                            value={minute}
                            onChange={e => setMinute(e.target.value)}
                            className="h-12 bg-foreground/5 border-foreground/5 focus:border-secondary/50 focus:ring-secondary/20 font-black italic text-xl text-foreground transition-all"
                            type="number"
                        />
                    </div>

                    {/* Player Selection */}
                    <div className="space-y-3 relative z-10">
                        <Label className="text-[10px] font-black tracking-widest text-secondary italic">
                            {eventType === 'substitution' ? t("player_out") : t("player")}
                        </Label>
                        <Select value={playerId} onValueChange={setPlayerId}>
                            <SelectTrigger className="h-12 bg-foreground/5 border-foreground/5 focus:ring-secondary/20 font-black italic tracking-widest text-foreground transition-all">
                                <SelectValue placeholder={t("player_name")} />
                            </SelectTrigger>
                            <SelectContent className="bg-card border-foreground/10">
                                {players.map((player) => (
                                    <SelectItem key={player.id} value={player.id} className="focus:bg-secondary focus:text-black font-black italic tracking-widest py-3">
                                        {player.number ? `#${player.number} ` : ""}{player.name}
                                    </SelectItem>
                                ))}
                                <SelectItem value="unknown" className="focus:bg-secondary focus:text-black font-black italic tracking-widest py-3">
                                    {t("unknown_player")}
                                </SelectItem>
                            </SelectContent>
                        </Select>
                    </div>

                    {/* Goal: Assist */}
                    {eventType === 'goal' && (
                        <div className="space-y-3 relative z-10">
                            <Label className="text-[10px] font-black tracking-widest text-secondary italic">{t("assist")}</Label>
                            <Select value={assistPlayerId} onValueChange={setAssistPlayerId}>
                                <SelectTrigger className="h-12 bg-foreground/5 border-foreground/5 focus:ring-secondary/20 font-black italic tracking-widest text-foreground transition-all">
                                    <SelectValue placeholder={t("no_assist")} />
                                </SelectTrigger>
                                <SelectContent className="bg-card border-foreground/10">
                                    <SelectItem value="none" className="focus:bg-secondary focus:text-black font-black italic tracking-widest py-3">{t("no_assist")}</SelectItem>
                                    {players.map((player) => (
                                        <SelectItem key={player.id} value={player.id} className="focus:bg-secondary focus:text-black font-black italic tracking-widest py-3">
                                            {player.number ? `#${player.number} ` : ""}{player.name}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                    )}

                    {/* Substitution: Player IN */}
                    {eventType === 'substitution' && (
                        <div className="space-y-3 relative z-10">
                            <Label className="text-[10px] font-black tracking-widest text-secondary italic">{t("player_in")}</Label>
                            <Select value={subInPlayerId} onValueChange={setSubInPlayerId}>
                                <SelectTrigger className="h-12 bg-foreground/5 border-foreground/5 focus:ring-secondary/20 font-black italic tracking-widest text-foreground transition-all">
                                    <SelectValue placeholder={t("select_player_in")} />
                                </SelectTrigger>
                                <SelectContent className="bg-card border-foreground/10">
                                    {players.map((player) => (
                                        <SelectItem key={player.id} value={player.id} className="focus:bg-secondary focus:text-black font-black italic tracking-widest py-3">
                                            {player.number ? `#${player.number} ` : ""}{player.name}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                    )}
                </div>

                <DialogFooter className="p-8 bg-foreground/5 flex flex-row gap-4 items-center sm:justify-start">
                    <Button 
                        type="button" 
                        variant="ghost" 
                        onClick={() => onOpenChange(false)}
                        className="flex-1 h-12 text-[10px] font-black tracking-widest text-foreground/40 hover:text-foreground hover:bg-foreground/5 transition-all"
                    >
                        {tCommon("cancel")}
                    </Button>
                    <Button 
                        type="button" 
                        onClick={handleSave} 
                        disabled={!playerId}
                        className="flex-1 h-12 bg-secondary text-black hover:bg-secondary/80 text-[10px] font-black tracking-widest transition-all skew-x-[-12deg] disabled:opacity-50 disabled:skew-x-0"
                    >
                        <span className="skew-x-[12deg] inline-block">{tCommon("save")}</span>
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

// Removed unused Timer, RotateCcw imports



interface MatchTimerProps {
    time: number;
    readOnly?: boolean;
    customText?: string | number | null;
    addedTime?: number | null;
}

export function MatchTimer({ time, readOnly = false, customText, addedTime }: MatchTimerProps) {
    const formatTime = (seconds: number) => {
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
    };

    return (
        <div className="flex flex-col items-center gap-3">
            <div className="flex items-center gap-3">
                <div className="text-2xl lg:text-6xl font-black tracking-tighter text-secondary tabular-nums drop-shadow-[0_0_15px_rgba(5,255,163,0.2)]">
                    {customText ? customText : formatTime(time)}
                </div>
            </div>
            {addedTime && (
                <div className="px-3 py-1 bg-secondary text-black text-[9px] font-black tracking-widest skew-x-[-12deg]">
                    <span className="skew-x-[12deg] inline-block">+{addedTime} MIN ADDED</span>
                </div>
            )}
        </div>
    );
}

"use client";

import { useState, useEffect, useMemo, useCallback } from "react";
import { PenaltyShot } from "@/types/index";
import { getPenaltyShootout, addPenaltyShot, clearPenaltyShootout } from "@/app/[locale]/organizer/tournaments/[id]/penalty-actions";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Loader2, Target, Check, X, Trash2, AlertTriangle } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";
import { useTranslations } from "next-intl";

interface PenaltyShootoutDialogProps {
    matchId: string;
    homeTeamId: string | null;
    awayTeamId: string | null;
    homeTeamName: string;
    awayTeamName: string;
    trigger?: React.ReactNode;
    onComplete?: (homeScore: number, awayScore: number) => void;
    onUpdate?: () => void;
}

export function PenaltyShootoutDialog({
    matchId,
    homeTeamId,
    awayTeamId,
    homeTeamName,
    awayTeamName,
    trigger,
    onComplete,
    onUpdate,
}: PenaltyShootoutDialogProps) {
    const { toast } = useToast();
    const t = useTranslations("Penalty");
    const [open, setOpen] = useState(false);
    const [shots, setShots] = useState<PenaltyShot[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [isSaving, setIsSaving] = useState(false);

    const fetchShots = useCallback(async () => {
        setIsLoading(true);
        const result = await getPenaltyShootout(matchId);
        if (result.success && result.data) {
            setShots(result.data);
        }
        setIsLoading(false);
    }, [matchId]);

    useEffect(() => {
        if (open) {
            const timer = setTimeout(() => fetchShots(), 0);
            return () => clearTimeout(timer);
        }
    }, [open, fetchShots]);

    const homeShots = shots.filter(s => s.team_id === homeTeamId);
    const awayShots = shots.filter(s => s.team_id === awayTeamId);
    const homeScore = homeShots.filter(s => s.scored).length;
    const awayScore = awayShots.filter(s => s.scored).length;

    // Calculate total display rounds:
    // - Always show at least 5 regulation rounds
    // - If all 5 are completed AND scores are tied, show sudden death rounds (current + 1 empty)
    const totalRounds = useMemo(() => {
        const completedHomRounds = homeShots.length;
        const completedAwayRounds = awayShots.length;
        const maxCompleted = Math.max(completedHomRounds, completedAwayRounds);

        if (maxCompleted < 5) {
            return 5; // Still in regulation
        }

        // All 5 regulation rounds done
        // If there's a winner after regulation OR during sudden death with equal shots, show + 1 for next round
        const isTied = homeScore === awayScore;
        const bothComplete = completedHomRounds === completedAwayRounds;

        if (isTied && bothComplete) {
            // Tied and both teams shot same number — show one more empty row for sudden death
            return maxCompleted + 1;
        }

        if (!bothComplete) {
            // One team hasn't shot yet this round — show current max
            return maxCompleted;
        }

        // Winner decided
        return maxCompleted;
    }, [homeShots.length, awayShots.length, homeScore, awayScore]);

    const isSuddenDeath = homeShots.length >= 5 || awayShots.length >= 5;

    const handleAddShot = async (teamId: string, scored: boolean) => {
        setIsSaving(true);
        const teamShots = shots.filter(s => s.team_id === teamId);
        const round = teamShots.length + 1;

        const result = await addPenaltyShot(matchId, teamId, round, scored);
        if (result.success) {
            await fetchShots();
            onUpdate?.();
        } else {
            toast({ title: "Error", description: result.error, variant: "destructive" });
        }
        setIsSaving(false);
    };

    const handleClear = async () => {
        if (!confirm(t("clear_confirm"))) return;
        await clearPenaltyShootout(matchId);
        setShots([]);
        onUpdate?.();
    };

    // Determine winner based on mathematical possibility
    const hasWinner = useMemo(() => {
        const hLen = homeShots.length;
        const aLen = awayShots.length;
        
        // 1. Regulation Phase (5 shots each)
        const hRemaining = Math.max(0, 5 - hLen);
        const aRemaining = Math.max(0, 5 - aLen);

        // Check if home team has already won
        if (homeScore > awayScore + aRemaining) return 'home';
        // Check if away team has already won
        if (awayScore > homeScore + hRemaining) return 'away';

        // 2. Sudden Death Phase (after 5 shots each and still tied)
        if (hLen >= 5 && aLen >= 5 && hLen === aLen) {
            if (homeScore > awayScore) return 'home';
            if (awayScore > homeScore) return 'away';
        }

        return null;
    }, [homeShots.length, awayShots.length, homeScore, awayScore]);    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                {trigger || (
                    <Button variant="outline" size="sm" className="h-12 border-foreground/5 bg-foreground/5 hover:bg-foreground/10 hover:border-secondary/50 transition-all group">
                        <Target className="h-4 w-4 mr-2" />
                        <span className="text-[10px] font-black tracking-widest">Penalty Shootout</span>
                    </Button>
                )}
            </DialogTrigger>
            <DialogContent className="bg-card border-foreground/5 p-0 overflow-hidden max-w-md">
                <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-secondary/50 via-secondary to-secondary/50" />
                
                <DialogHeader className="p-8 pb-4 text-left">
                    <DialogTitle className="flex items-center gap-4 text-2xl font-black tracking-tighter text-foreground">
                        <div className="p-2 bg-secondary/10 border border-secondary/20">
                            <Target className="h-6 w-6 text-secondary" />
                        </div>
                        {t("title")}
                    </DialogTitle>
                    <p className="text-[10px] font-black tracking-[0.2em] text-muted-foreground/40 mt-2">DECISIVE SHOOTOUT SESSION</p>
                </DialogHeader>

                {isLoading ? (
                    <div className="flex justify-center py-16">
                        <Loader2 className="h-8 w-8 animate-spin text-secondary" />
                    </div>
                ) : (
                    <div className="px-8 pb-8 space-y-8 relative">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-secondary/5 -rotate-12 translate-x-12 -translate-y-12 pointer-events-none" />

                        {/* Score Summary Scoreboard Style */}
                        <div className="flex items-center justify-center gap-10 py-6 bg-foreground/5 border border-foreground/5 relative z-10 overflow-hidden">
                            <div className="absolute inset-0 bg-gradient-to-b from-foreground/5 to-transparent pointer-events-none" />
                            <div className="text-center relative z-10">
                                <p className="text-[9px] font-black tracking-widest text-foreground/40 mb-2 truncate max-w-[120px]">{homeTeamName}</p>
                                <span className={cn(
                                    "text-5xl font-black tracking-tighter transition-all",
                                    hasWinner === 'home' ? "text-secondary drop-shadow-[0_0_10px_rgba(5,255,163,0.3)]" : "text-foreground"
                                )}>
                                    {homeScore}
                                </span>
                            </div>
                            <span className="text-foreground/20 text-3xl font-black tracking-tighter relative z-10">-</span>
                            <div className="text-center relative z-10">
                                <p className="text-[9px] font-black tracking-widest text-foreground/40 mb-2 truncate max-w-[120px]">{awayTeamName}</p>
                                <span className={cn(
                                    "text-5xl font-black tracking-tighter transition-all",
                                    hasWinner === 'away' ? "text-secondary drop-shadow-[0_0_10px_rgba(5,255,163,0.3)]" : "text-foreground"
                                )}>
                                    {awayScore}
                                </span>
                            </div>
                        </div>

                        {/* Winner/Status Banner */}
                        {hasWinner ? (
                            <div className="text-center py-3 bg-secondary/10 border border-secondary/20 relative z-10 overflow-hidden group">
                                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-foreground/5 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
                                <p className="text-xs font-black tracking-widest text-secondary relative z-10">
                                    🏆 {t("wins_on_penalties", { team: hasWinner === 'home' ? homeTeamName : awayTeamName })}
                                </p>
                            </div>
                        ) : isSuddenDeath ? (
                            <div className="flex items-center justify-center relative z-10">
                                <Badge className="bg-amber-500/10 text-amber-500 border-amber-500/20 px-4 py-1 animate-pulse">
                                    <AlertTriangle className="h-3 w-3 mr-2" />
                                    <span className="text-[10px] font-black tracking-[0.2em]">{t("sudden_death")}</span>
                                </Badge>
                            </div>
                        ) : null}

                        {/* Shot Grid */}
                        <div className="grid grid-cols-[1fr_auto_1fr] gap-x-6 gap-y-4 relative z-10">
                            <div className="text-[9px] font-black tracking-widest text-foreground/20 text-center">{homeTeamName}</div>
                            <div className="w-8" />
                            <div className="text-[9px] font-black tracking-widest text-foreground/20 text-center">{awayTeamName}</div>

                            {Array.from({ length: totalRounds }, (_, i) => {
                                const homeShot = homeShots[i];
                                const awayShot = awayShots[i];
                                const isSD = i >= 5;

                                return (
                                    <div key={i} className="contents">
                                        {/* Home Shot */}
                                        <div className="flex justify-center">
                                            {homeShot ? (
                                                <div className={cn(
                                                    "w-12 h-12 flex items-center justify-center border transition-all",
                                                    homeShot.scored ? "bg-secondary/10 border-secondary/30 text-secondary" : "bg-red-500/10 border-red-500/30 text-red-500"
                                                )}>
                                                    {homeShot.scored ? <Check className="h-6 w-6 stroke-[3px]" /> : <X className="h-6 w-6 stroke-[3px]" />}
                                                </div>
                                            ) : !hasWinner ? (
                                                <div className="flex gap-2">
                                                    <button
                                                        className="w-12 h-12 border border-foreground/5 bg-foreground/5 hover:bg-secondary hover:text-black hover:border-secondary flex items-center justify-center group/btn transition-all disabled:opacity-20"
                                                        onClick={() => homeTeamId && handleAddShot(homeTeamId, true)}
                                                        disabled={isSaving || !homeTeamId}
                                                    >
                                                        <Check className="h-5 w-5 group-hover/btn:scale-110 transition-transform" />
                                                    </button>
                                                    <button
                                                        className="w-12 h-12 border border-foreground/5 bg-foreground/5 hover:bg-red-500 hover:text-foreground hover:border-red-500 flex items-center justify-center group/btn transition-all disabled:opacity-20"
                                                        onClick={() => homeTeamId && handleAddShot(homeTeamId, false)}
                                                        disabled={isSaving || !homeTeamId}
                                                    >
                                                        <X className="h-5 w-5 group-hover/btn:scale-110 transition-transform" />
                                                    </button>
                                                </div>
                                            ) : (
                                                <div className="w-12 h-12 border border-foreground/2 bg-foreground/2 opacity-20" />
                                            )}
                                        </div>

                                        {/* Round Number */}
                                        <div className="flex items-center justify-center">
                                            <span className={cn(
                                                "text-xs font-black italic tracking-tighter",
                                                isSD ? "text-amber-500" : "text-foreground/40"
                                            )}>
                                                {isSD ? `SD${i - 4}` : i + 1}
                                            </span>
                                        </div>

                                        {/* Away Shot */}
                                        <div className="flex justify-center">
                                            {awayShot ? (
                                                <div className={cn(
                                                    "w-12 h-12 flex items-center justify-center border transition-all",
                                                    awayShot.scored ? "bg-secondary/10 border-secondary/30 text-secondary" : "bg-red-500/10 border-red-500/30 text-red-500"
                                                )}>
                                                    {awayShot.scored ? <Check className="h-6 w-6 stroke-[3px]" /> : <X className="h-6 w-6 stroke-[3px]" />}
                                                </div>
                                            ) : !hasWinner ? (
                                                <div className="flex gap-2">
                                                    <button
                                                        className="w-12 h-12 border border-foreground/5 bg-foreground/5 hover:bg-secondary hover:text-black hover:border-secondary flex items-center justify-center group/btn transition-all disabled:opacity-20"
                                                        onClick={() => awayTeamId && handleAddShot(awayTeamId, true)}
                                                        disabled={isSaving || !awayTeamId}
                                                    >
                                                        <Check className="h-5 w-5 group-hover/btn:scale-110 transition-transform" />
                                                    </button>
                                                    <button
                                                        className="w-12 h-12 border border-foreground/5 bg-foreground/5 hover:bg-red-500 hover:text-foreground hover:border-red-500 flex items-center justify-center group/btn transition-all disabled:opacity-20"
                                                        onClick={() => awayTeamId && handleAddShot(awayTeamId, false)}
                                                        disabled={isSaving || !awayTeamId}
                                                    >
                                                        <X className="h-5 w-5 group-hover/btn:scale-110 transition-transform" />
                                                    </button>
                                                </div>
                                            ) : (
                                                <div className="w-12 h-12 border border-foreground/2 bg-foreground/2 opacity-20" />
                                            )}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>

                        {/* Actions */}
                        <div className="flex flex-col gap-3 pt-4 border-t border-foreground/5 relative z-10">
                            {shots.length > 0 && (
                                <Button 
                                    variant="ghost" 
                                    className="h-10 text-[9px] font-black tracking-widest text-red-500/40 hover:text-red-500 hover:bg-red-500/10 transition-all" 
                                    onClick={handleClear}
                                >
                                    <Trash2 className="h-3 w-3 mr-2" />
                                    {t("clear_all")}
                                </Button>
                            )}
                            <Button 
                                variant="ghost" 
                                onClick={() => setOpen(false)}
                                className="h-10 text-[9px] font-black tracking-widest text-foreground/40 hover:text-foreground hover:bg-foreground/5"
                            >
                                CLOSE SESSION
                            </Button>
                        </div>
                    </div>
                )}
            </DialogContent>
        </Dialog>
    );
}

import { Match, EventType } from "@/types";
import { useTranslations } from "next-intl";
import Image from "next/image";
import { MatchTimer } from "./match-timer";

interface ScoreboardProps {
    match: Match;
    homeScore: number;
    awayScore: number;
    onTeamClick?: (teamId: string) => void;
    // Timer props
    timerTime?: number;
    timerReadOnly?: boolean;
    timerCustomText?: string | number | null;
    onAddTime?: () => void;
    addedTime?: number | null;
}

export function Scoreboard({ match, homeScore, awayScore, onTeamClick, timerTime, timerReadOnly, timerCustomText, onAddTime, addedTime }: ScoreboardProps) {
    const t = useTranslations("Console");

    const formatTeamName = (name: string | undefined) => {
        if (!name) return "";
        return name.length > 8 ? `${name.substring(0, 8).trim()}...` : name;
    };

    return (
        <div className="bg-foreground/5 border border-foreground/5 relative overflow-hidden w-full group">
            {/* Background Decorative Element */}
            <div className="absolute top-0 right-0 w-32 h-32 bg-secondary/5 -rotate-12 translate-x-8 -translate-y-8 pointer-events-none" />
            <div className="absolute bottom-0 left-0 w-48 h-1 bg-gradient-to-r from-secondary/50 to-transparent" />
            
            <div className="p-4 lg:p-6 flex flex-col items-center justify-center relative z-10 w-full">
                <div className="flex items-center justify-between w-full max-w-5xl gap-4 md:gap-12">
                    <div 
                        className="flex-1 text-center md:text-right space-y-2 md:space-y-3 cursor-pointer group/home"
                        onClick={() => onTeamClick?.(match.home_team_id || "")}
                    >
                        <div className="inline-flex items-center justify-center w-16 h-16 md:w-24 md:h-24 bg-foreground/5 border border-foreground/10 p-2 md:p-3 relative group/logo">
                            <div className="absolute inset-0 bg-secondary/5 scale-0 group-hover/logo:scale-100 transition-transform duration-500" />
                            {match.home_team?.logo_url ? (
                                <Image src={match.home_team.logo_url} width={64} height={64} className="w-16 h-16 object-contain relative z-10" alt="" unoptimized />
                            ) : (
                                <span className="text-2xl font-black text-foreground/20 relative z-10">{match.home_team?.name?.substring(0, 2).toUpperCase() || 'H'}</span>
                            )}
                        </div>
                        <div className="space-y-1">
                            <h2 className="text-2xl lg:text-4xl font-black tracking-tighter text-foreground truncate group-hover/home:text-secondary transition-colors">
                                {formatTeamName(match.home_team?.name)}
                            </h2>
                            <p className="text-[10px] font-black tracking-[0.3em] text-secondary/60">HOME</p>
                        </div>
                    </div>

                    {/* Central Score Area */}
                    <div className="flex flex-col items-center gap-4 md:gap-6 px-0 md:px-6 md:border-x border-foreground/5">
                        <div className="px-4 py-1.5 bg-secondary/10 border border-secondary/20 skew-x-[-12deg]">
                            <span className="text-[10px] font-black tracking-[0.2em] text-secondary skew-x-[12deg] inline-block">
                                {match.stage || "Tournament Match"}
                            </span>
                        </div>

                        <div className="flex items-center gap-4 md:gap-6 tabular-nums">
                            <span className="text-5xl md:text-7xl lg:text-9xl font-black tracking-tighter text-foreground">{homeScore}</span>
                            <div className="flex flex-col items-center gap-2">
                                <span className="text-secondary text-2xl lg:text-4xl font-black opacity-30 animate-pulse">-</span>
                            </div>
                            <span className="text-5xl md:text-7xl lg:text-9xl font-black tracking-tighter text-foreground">{awayScore}</span>
                        </div>
                        
                        {timerTime !== undefined && (
                            <MatchTimer
                                time={timerTime}
                                readOnly={timerReadOnly}
                                customText={timerCustomText}
                                onAddTime={onAddTime}
                                addedTime={addedTime}
                            />
                        )}

                        {match.status === 'finished' && (
                            <div className="bg-secondary/20 text-secondary border border-secondary/30 px-4 py-1 text-[10px] font-black tracking-[0.2em]">
                                Final Result
                            </div>
                        )}
                    </div>

                    <div 
                        className="flex-1 text-center md:text-left space-y-4 cursor-pointer group/away"
                        onClick={() => onTeamClick?.(match.away_team_id || "")}
                    >
                        <div className="inline-flex items-center justify-center w-16 h-16 md:w-24 md:h-24 bg-foreground/5 border border-foreground/10 p-2 md:p-3 relative group/logo">
                            <div className="absolute inset-0 bg-foreground/5 scale-0 group-hover/logo:scale-100 transition-transform duration-500" />
                            {match.away_team?.logo_url ? (
                                <Image src={match.away_team.logo_url} width={64} height={64} className="w-16 h-16 object-contain relative z-10" alt="" unoptimized />
                            ) : (
                                <span className="text-2xl font-black text-foreground/20 relative z-10">{match.away_team?.name?.substring(0, 2).toUpperCase() || 'A'}</span>
                            )}
                        </div>
                        <div className="space-y-1">
                            <h2 className="text-2xl lg:text-4xl font-black tracking-tighter text-foreground truncate group-hover/away:text-secondary transition-colors">
                                {formatTeamName(match.away_team?.name)}
                            </h2>
                            <p className="text-[10px] font-black tracking-[0.3em] text-foreground/40">AWAY</p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { useRouter } from "next/navigation";
import { useTranslations } from "next-intl";
import { getPlayers } from "@/app/[locale]/organizer/tournaments/[id]/player-actions";
import { updateMatch } from "@/app/[locale]/organizer/tournaments/[id]/actions";
import { getPenaltyShootout } from "@/app/[locale]/organizer/tournaments/[id]/penalty-actions";
import { createClient } from "@/lib/supabase/client";

import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { cn } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";
import {
    Timer,
    ArrowLeft,
    Target,
    Undo,
    Ban,
    Activity,
    Square,
    Repeat,
    Flag,
    Trophy,
    Stethoscope,
    Shield
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { Link } from "@/i18n/routing";

// Types
import { Match, Player, EventType, MatchEvent, PenaltyShot } from "@/types";

// Components & Hooks
import { MatchControls } from "./console/match-controls";
import { Scoreboard } from "./console/scoreboard";
import { EventTimeline } from "./console/event-timeline";
import { MatchEventDialog } from "./console/match-event-dialog";
import { WalkoverDialog } from "./console/walkover-dialog";
import { PenaltyShootoutDialog } from "./console/penalty-shootout-dialog";
import { AddTimeDialog, SetTimeDialog } from "./console/time-dialogs";
import { useMatchTimer } from "@/hooks/use-match-timer";
import { useMatchEvents } from "@/hooks/use-match-events";
import { EVENT_TYPES } from "./console/constants";

interface MatchConsolePageProps {
    match: Match;
    tournamentId: string;
    isPro?: boolean;
    readOnly?: boolean;
    initialEvents?: MatchEvent[];
    backUrl: string;
    tournamentName?: string;
}

export function MatchConsolePage({ match: initialMatch, tournamentId, isPro = false, readOnly = false, initialEvents, backUrl, tournamentName }: MatchConsolePageProps) {
    const t = useTranslations("Console");
    const tMatch = useTranslations("Match");
    const tCommon = useTranslations("Common");
    const tPublic = useTranslations("PublicView");
    const router = useRouter();
    const { toast } = useToast();

    // --- State ---
    const [match, setMatch] = useState<Match>(initialMatch);
    const [homePlayers, setHomePlayers] = useState<Player[]>([]);
    const [awayPlayers, setAwayPlayers] = useState<Player[]>([]);

    // Hooks
    const { events, addEvent, deleteEvent } = useMatchEvents(match.id, tournamentId, initialEvents, readOnly);
    const { time, setTime, isRunning, setIsRunning } = useMatchTimer(match, tournamentId, events);

    // Dialog States
    const [eventDialogOpen, setEventDialogOpen] = useState(false);
    const [woDialogOpen, setWoDialogOpen] = useState(false);
    const [addTimeDialogOpen, setAddTimeDialogOpen] = useState(false);
    const [setTimeDialogOpen, setSetTimeDialogOpen] = useState(false);
    const [penaltyShots, setPenaltyShots] = useState<PenaltyShot[]>([]);

    // Event Selection State
    const [selectedTeamId, setSelectedTeamId] = useState<string>("");
    const [selectedEventType, setSelectedEventType] = useState<EventType | null>(null);

    // --- Effects ---
    useEffect(() => {
        setMatch(initialMatch);
    }, [initialMatch]);

    useEffect(() => {
        const loadPlayers = async () => {
            const fetchTeam = async (id: string, setter: (players: Player[]) => void) => {
                const res = await getPlayers(id);
                if (res.success && res.data) setter(res.data);
            };
            if (match.home_team_id) fetchTeam(match.home_team_id, setHomePlayers);
            if (match.away_team_id) fetchTeam(match.away_team_id, setAwayPlayers);
        };
        loadPlayers();
    }, [match.home_team_id, match.away_team_id]);

    const fetchShots = useCallback(async () => {
        const res = await getPenaltyShootout(match.id);
        if (res.success && res.data) {
            setPenaltyShots(res.data);
        }
    }, [match.id]);

    useEffect(() => {
        fetchShots();
    }, [fetchShots]);

    useEffect(() => {
        const supabase = createClient();
        const channel = supabase
            .channel(`match-${match.id}`)
            .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'matches', filter: `id=eq.${match.id}` }, (payload) => {
                const _newData = payload.new as Match;
                setMatch(prev => ({ ...prev, ..._newData }));
            })
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [match.id]);

    // --- Computed Data ---
    const isHomeTeam = (id: string) => id === match.home_team_id || id === match.home_team?.id;
    const isAwayTeam = (id: string) => id === match.away_team_id || id === match.away_team?.id;

    const homeScore = events.filter((e: MatchEvent) => e.team_id && isHomeTeam(e.team_id) && e.event_type === 'goal').length;
    const awayScore = events.filter((e: MatchEvent) => e.team_id && isAwayTeam(e.team_id) && e.event_type === 'goal').length;
    const allPlayers = [...homePlayers, ...awayPlayers];

    // --- Handlers ---
    const handleStartMatch = async () => {
        if (readOnly) return;
        const currentMinute = Math.floor(time / 60) + 1;
        const teamId = match.home_team_id || match.away_team_id;
        const resolvedTeamId = match.home_team?.id || match.away_team?.id || teamId;

        const backupMatch = { ...match };
        const backupIsRunning = isRunning;

        // Optimistic UI Update
        setIsRunning(true);
        setMatch(prev => ({ ...prev, status: 'live', timer_status: 'playing' }));

        try {
            if (resolvedTeamId) {
                const res = await addEvent(null, 'kick_off', currentMinute, null, { start_timestamp: Date.now() }, "Kick Off");
                if (!res.success) throw new Error(`${res.error || "Failed to add kick-off"} (Team: ${resolvedTeamId})`);
            } else {
                throw new Error("Missing team IDs for kick-off");
            }

            const updateRes = await updateMatch(match.id, { status: 'live', timer_status: 'playing', elapsed_before_pause: time, current_minute: currentMinute }, tournamentId);
            if (!updateRes.success) throw new Error(`${updateRes.error || "Failed to update match"} (Match: ${match.id})`);

            toast({ title: t("match_started") || "Match Started" });
        } catch (error) {
            console.error("Start match error:", error);
            setIsRunning(backupIsRunning);
            setMatch(backupMatch);
            toast({
                title: "Error starting match",
                description: `${error instanceof Error ? error.message : String(error)} (Match: ${match.id.substring(0, 8)})`,
                variant: "destructive"
            });
        }
    };

    const handlePauseMatch = async () => {
        if (readOnly) return;
        const currentMinute = Math.floor(time / 60) + 1;
        const teamId = match.home_team_id || match.away_team_id;
        const resolvedTeamId = match.home_team?.id || match.away_team?.id || teamId;

        const backupMatch = { ...match };
        const backupIsRunning = isRunning;

        // Optimistic UI Update
        setIsRunning(false);
        setMatch(prev => ({ ...prev, timer_status: 'paused', elapsed_before_pause: time }));

        try {
            if (resolvedTeamId) {
                const res = await addEvent(null, 'match_paused', currentMinute, null, {}, "Match Paused");
                if (!res.success) throw new Error(`${res.error || "Failed to add match pause"} (Team: ${resolvedTeamId})`);
            }
            // Clear any 'add_time' events when pausing, so it's reset for the next resumption
            const addTimeEvents = events.filter(e => e.event_type === 'add_time');
            for (const e of addTimeEvents) {
                await deleteEvent(e.id);
            }

            const updateRes = await updateMatch(match.id, { timer_status: 'paused', elapsed_before_pause: time, current_minute: currentMinute }, tournamentId);
            if (!updateRes.success) throw new Error(`${updateRes.error || "Failed to update match balance"} (Match: ${match.id})`);

            toast({ title: t("match_paused") || "Match Paused" });
        } catch (error) {
            console.error("Pause match error:", error);
            setIsRunning(backupIsRunning);
            setMatch(backupMatch);
            toast({
                title: "Error pausing match",
                description: `${error instanceof Error ? error.message : String(error)} (Match: ${match.id.substring(0, 8)})`,
                variant: "destructive"
            });
        }
    };

    const handleResumeMatch = async () => {
        if (readOnly) return;
        const currentMinute = Math.floor(time / 60) + 1;
        const teamId = match.home_team_id || match.away_team_id;
        const resolvedTeamId = match.home_team?.id || match.away_team?.id || teamId;

        const backupMatch = { ...match };
        const backupIsRunning = isRunning;

        // Optimistic UI Update
        setIsRunning(true);
        setMatch(prev => ({ ...prev, timer_status: 'playing' }));

        try {
            if (resolvedTeamId) {
                const res = await addEvent(null, 'match_resumed', currentMinute, null, { start_timestamp: Date.now() }, "Match Resumed");
                if (!res.success) throw new Error(`${res.error || "Failed to add match resume"} (Team: ${resolvedTeamId})`);
            }
            const updateRes = await updateMatch(match.id, { timer_status: 'playing', current_minute: Math.floor(time / 60) + 1 }, tournamentId);
            if (!updateRes.success) throw new Error(`${updateRes.error || "Failed to update match resume"} (Match: ${match.id})`);

            toast({ title: t("match_resumed") || "Match Resumed" });
        } catch (error) {
            console.error("Resume match error:", error);
            setIsRunning(backupIsRunning);
            setMatch(backupMatch);
            toast({
                title: "Error resuming match",
                description: `${error instanceof Error ? error.message : String(error)} (Match: ${match.id.substring(0, 8)})`,
                variant: "destructive"
            });
        }
    };

    const handleEndMatch = async () => {
        if (!confirm(t("confirm_end"))) return;
        const currentMinute = Math.floor(time / 60) + 1;
        const teamId = match.home_team_id || match.away_team_id;
        await addEvent(null, 'full_time', currentMinute, null, {}, "Full Time");
        setIsRunning(false);
        await updateMatch(match.id, { status: 'finished', home_score: homeScore, away_score: awayScore, current_minute: currentMinute }, tournamentId);
    };

    const handleWalkover = async (winnerId: string) => {
        if (!confirm(t("confirm_walkover"))) return;
        const isHomeWinner = winnerId === match.home_team_id;
        await updateMatch(match.id, { status: 'finished', home_score: isHomeWinner ? 3 : 0, away_score: isHomeWinner ? 0 : 3, winner_id: winnerId }, tournamentId);
        setWoDialogOpen(false);
        router.refresh();
    };

    const handleUndo = async () => {
        if (readOnly) return;
        const lastEvent = events.find((e: MatchEvent) => !e.id.startsWith("temp-"));
        if (!lastEvent) return toast({ title: t("no_events") });

        const evtConfig = EVENT_TYPES.find(e => e.type === lastEvent.event_type);
        const label = evtConfig ? t(evtConfig.label) : lastEvent.event_type;

        if (!confirm(`${tCommon("delete")} '${label}'?`)) return;
        await deleteEvent(lastEvent.id);
    };

    const handleQuickAction = (teamId: string, type: EventType) => {
        if (readOnly) return;
        if (type === 'corner') {
            const minute = Math.floor(time / 60) + 1;
            addEvent(teamId, 'corner', minute, null, {}, "Corner");
            return;
        }
        if (!isPro && type === 'goal') {
            const minute = Math.floor(time / 60) + 1;
            addEvent(teamId, 'goal', minute, null, {}, "Goal");
            return;
        }
        setSelectedTeamId(teamId);
        setSelectedEventType(type);
        setEventDialogOpen(true);
    };

    const handleSaveEvent = async (data: { minute: number; playerId: string; extraInfo: Record<string, unknown>; autoRed?: boolean }) => {
        if (!selectedTeamId || !selectedEventType) return;
        const player = allPlayers.find(p => p.id === data.playerId);
        const playerName = player ? player.name : "Unknown";
        await addEvent(selectedTeamId, data.autoRed ? 'red_card' : selectedEventType, data.minute, data.playerId, data.extraInfo, playerName);
    };

    const handleSetTime = async (minutes: number, seconds: number) => {
        const totalSeconds = (minutes * 60) + seconds;
        setTime(totalSeconds);
        const currentMinute = Math.ceil((totalSeconds || 1) / 60);
        await updateMatch(match.id, { elapsed_before_pause: totalSeconds, current_minute: currentMinute }, tournamentId);
        setSetTimeDialogOpen(false);
    };

    const lastAddTimeEvent = [...events].reverse().find(e => e.event_type === 'add_time' && !e.id.startsWith("temp-"));
    const addedTime = lastAddTimeEvent?.extra_info?.added_minutes || null;

    // --- Team Action Grid Component ---
    const TeamActionGrid = ({ teamId, name, type }: { teamId: string, name: string, type: 'home' | 'away' }) => {
        const actions = [
            { type: 'goal', label: t("goal"), icon: Trophy, color: 'hover:bg-secondary hover:text-black hover:border-secondary' },
            { type: 'yellow_card', label: t("yellow_card"), icon: Square, color: 'hover:bg-yellow-400 hover:text-black hover:border-yellow-400', iconColor: 'text-yellow-500' },
            { type: 'red_card', label: t("red_card"), icon: Square, color: 'hover:bg-red-500 hover:text-foreground hover:border-red-500', iconColor: 'text-red-500' },
            { type: 'substitution', label: t("substitution"), icon: Repeat, color: 'hover:bg-blue-500 hover:text-foreground hover:border-blue-500' },
            { type: 'foul', label: t("foul") || "Foul", icon: Activity, color: 'hover:bg-orange-500 hover:text-foreground hover:border-orange-500' },
            { type: 'penalty', label: t("penalty") || "Penalty", icon: Target, color: 'hover:bg-indigo-600 hover:text-foreground hover:border-indigo-600' },
            { type: 'save', label: t("save") || "Save", icon: Shield, color: 'hover:bg-teal-600 hover:text-foreground hover:border-teal-600' },
            { type: 'injury', label: t("injury") || "Injury", icon: Stethoscope, color: 'hover:bg-amber-600 hover:text-foreground hover:border-amber-600' },
            { type: 'corner', label: t("corner") || "Corner", icon: Flag, color: 'hover:bg-cyan-500 hover:text-black hover:border-foreground' },
        ];

        return (
            <div className="bg-foreground/5 border border-foreground/5 p-4 md:p-6 relative overflow-hidden group">
                <div className={cn(
                    "absolute top-0 left-0 w-1 h-full translate-y-full group-hover:translate-y-0 transition-transform duration-500",
                    type === 'home' ? "bg-secondary" : "bg-foreground/40"
                )} />
                <div className="absolute -right-4 -top-4 w-24 h-24 bg-foreground/5 rotate-12 transition-transform group-hover:scale-110" />

                <div className="relative z-10 space-y-2 md:space-y-3">
                    <div className="space-y-1 pb-2 md:pb-3 border-b border-foreground/5">
                        <h3 className="text-xl font-black tracking-tighter text-foreground">{name}</h3>
                        <p className="text-[9px] text-muted-foreground tracking-widest">{type === 'home' ? 'Home' : 'Away'} Team Actions</p>
                    </div>

                    <div className="grid grid-cols-3 gap-2 md:gap-3">
                        {actions.map((action) => (
                            <Button
                                variant="outline"
                                key={action.type}
                                onClick={() => handleQuickAction(teamId, action.type as EventType)}
                                className={cn(
                                    "group flex flex-col items-center justify-center h-20 border-foreground/5 bg-foreground/5 transition-all duration-300",
                                    action.color
                                )}
                            >
                                <action.icon className={cn("h-5 w-5 mb-1 transition-transform group-hover:scale-110", action.iconColor)} />
                                <span className="hidden md:inline text-[9px] font-black tracking-widest">{action.label}</span>
                            </Button>
                        ))}
                    </div>
