                    </div>
                )}
            </header>

            <main className="flex-1 mx-auto w-full grid grid-cols-12 gap-2 md:gap-3 max-w-[1600px]">
                {/* Sidebar: Admin Controls or Match Info */}
                <aside className="col-span-12 lg:col-span-3 lg:row-span-2 gap-2 md:gap-3 order-2 lg:order-1 flex flex-col">
                        {/* Match Controls */}
                        <div className="bg-foreground/5 border border-foreground/5 p-4 md:p-6 relative overflow-hidden group">
                                <div className="absolute top-0 left-0 w-1 h-full bg-secondary translate-y-full group-hover:translate-y-0 transition-transform duration-500" />
                                <div className="absolute -right-4 -top-4 w-24 h-24 bg-secondary/5 rotate-12 transition-transform group-hover:scale-110" />

                                <div className="relative z-10 space-y-2 md:space-y-3">
                                    <div className="space-y-1 pb-2 md:pb-3 border-b border-foreground/5">
                                        <h4 className="text-[10px] font-black tracking-widest text-secondary">{readOnly ? tMatch("status") || "Match Status" : t("match_controls")}</h4>
                                        <p className="text-[9px] text-muted-foreground">{readOnly ? "Real-time match updates" : "Real-time session management"}</p>
                                    </div>
                                    {readOnly ? (
                                        <div className="space-y-4">
                                            <div className="flex items-center justify-between">
                                                <span className="text-[10px] font-black tracking-widest text-foreground/40">{t("tournament") || "Tournament"}</span>
                                                <span className="text-[10px] font-black italic text-foreground truncate max-w-[120px]">{tournamentName}</span>
                                            </div>
                                            <div className="flex items-center justify-between">
                                                <span className="text-[10px] font-black tracking-widest text-foreground/40">{t("stage") || "Stage"}</span>
                                                <span className="text-[10px] font-black italic text-secondary">{match.stage || "Regular"}</span>
                                            </div>
                                            <div className="pt-4 border-t border-foreground/5">
                                                <div className="flex flex-col items-center gap-2 py-4 bg-secondary/5 border border-secondary/10">
                                                    <Timer className="w-6 h-6 text-secondary animate-pulse" />
                                                    <span className="text-[8px] font-black tracking-[0.3em] text-secondary/60">LIVE UPDATES ACTIVE</span>
                                                </div>
                                            </div>
                                        </div>
                                    ) : (
                                        <MatchControls
                                            status={match.status}
                                            isRunning={isRunning}
                                            readOnly={false}
                                            onStart={handleStartMatch}
                                            onPause={handlePauseMatch}
                                            onResume={handleResumeMatch}
                                            onEnd={handleEndMatch}
                                            onSetTime={() => setSetTimeDialogOpen(true)}
                                            onAddTime={() => setAddTimeDialogOpen(true)}
                                        />
                                    )}
                                </div>
                            </div>

                        {!readOnly && (
                            <div className="bg-foreground/5 border border-foreground/5 p-4 md:p-6 relative overflow-hidden group">
                                <div className="absolute top-0 left-0 w-1 h-full bg-secondary translate-y-full group-hover:translate-y-0 transition-transform duration-500" />

                                <div className="relative z-10 space-y-2 md:space-y-3">
                                    <div className="space-y-1 pb-2 md:pb-3 border-b border-foreground/5">
                                        <h4 className="text-[10px] font-black tracking-widest text-secondary">{t("quick_actions")}</h4>
                                        <p className="text-[9px] text-muted-foreground italic">Admin session tools</p>
                                    </div>
                                    <div className="grid grid-cols-3 md:grid-cols-1 gap-2">
                                        <Button
                                            variant="outline"
                                            onClick={handleUndo}
                                            className="w-full flex justify-center md:justify-start items-center gap-3 h-12 border-foreground/5 bg-foreground/5 hover:bg-foreground/10 hover:border-secondary/50 transition-all group"
                                        >
                                            <Undo className="h-4 w-4 text-muted-foreground group-hover:text-secondary" />
                                            <span className="hidden md:inline text-[10px] font-black tracking-widest">{t("undo")}</span>
                                        </Button>
                                        <PenaltyShootoutDialog
                                            matchId={match.id}
                                            homeTeamId={match.home_team_id}
                                            awayTeamId={match.away_team_id}
                                            homeTeamName={match.home_team?.name || 'Home'}
                                            awayTeamName={match.away_team?.name || 'Away'}
                                            onUpdate={fetchShots}
                                            trigger={
                                                <Button
                                                    variant="outline"
                                                    className="w-full flex justify-center md:justify-start items-center gap-3 h-12 border-foreground/5 bg-foreground/5 hover:bg-foreground/10 hover:border-secondary/50 transition-all group"
                                                >
                                                    <Target className="h-4 w-4 text-muted-foreground group-hover:text-secondary" />
                                                    <span className="hidden md:inline text-[10px] font-black tracking-widest">{t("penalty_shootout")}</span>
                                                </Button>
                                            }
                                        />
                                        <Button
                                            variant="outline"
                                            onClick={() => setWoDialogOpen(true)}
                                            className="w-full flex justify-center md:justify-start items-center gap-3 h-12 border-foreground/5 bg-red-500/5 hover:bg-red-500/10 border-red-500/10 hover:border-red-500/30 transition-all group"
                                        >
                                            <Ban className="h-4 w-4 text-red-500/50 group-hover:text-red-500" />
                                            <span className="hidden md:inline text-[10px] font-black tracking-widest text-red-500/70 group-hover:text-red-500">WO {t("walkover")}</span>
                                        </Button>
                                    </div>
                                </div>
                            </div>
                        )}
                    </aside>

                {/* Scoreboard Section */}
                <section className="flex flex-col gap-2 md:gap-3 col-span-12 lg:col-span-9 order-1 lg:order-2">
                    <Scoreboard
                        match={match}
                        homeScore={homeScore}
                        awayScore={awayScore}
                        isPro={isPro}
                        readOnly={readOnly}
                        onAction={handleQuickAction}
                        onTeamClick={(teamId) => {
                            setSelectedTeamId(teamId);
                            setEventDialogOpen(true);
                        }}
                        timerTime={time}
                        timerReadOnly={readOnly || match.status === 'finished'}
                        timerCustomText={match.status === 'finished' ? (match.current_minute || "FT") : null}
                        addedTime={isRunning ? addedTime : null}
                    />

                    {!readOnly && (
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-2 md:gap-3">
                            <TeamActionGrid teamId={match.home_team_id!} name={match.home_team?.name || 'Home'} type="home" />
                            <TeamActionGrid teamId={match.away_team_id!} name={match.away_team?.name || 'Away'} type="away" />
                        </div>
                    )}
                </section>

                {/* Timeline Section */}
                <section className="flex flex-col gap-6 col-span-12 lg:col-span-9 order-3 lg:order-3">
                    <EventTimeline
                        events={[
                            ...events,
                            ...penaltyShots.map((ps: PenaltyShot) => ({
                                id: ps.id, match_id: ps.match_id, team_id: ps.team_id, player_id: ps.player_id, event_type: 'penalty_shot' as const, minute: 120, extra_info: { scored: ps.scored, round: ps.round }, created_at: ps.created_at, player_name: ps.player?.name
                            }))
                        ].sort((a: MatchEvent, b: MatchEvent) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())}
                        match={match}
                        players={allPlayers}
                        readOnly={readOnly}
                        onDelete={deleteEvent}
                    />
                </section>
            </main>

            {/* Dialogs */}
            <MatchEventDialog open={eventDialogOpen} onOpenChange={setEventDialogOpen} teamId={selectedTeamId} eventType={selectedEventType} initialMinute={Math.floor(time / 60) + 1} players={selectedTeamId === match.home_team_id ? homePlayers : awayPlayers} existingEvents={events} onSave={handleSaveEvent} />
            <WalkoverDialog open={woDialogOpen} onOpenChange={setWoDialogOpen} match={match} onConfirm={handleWalkover} />
            <SetTimeDialog open={setTimeDialogOpen} onOpenChange={setSetTimeDialogOpen} currentTime={time} onSave={handleSetTime} />
            <AddTimeDialog open={addTimeDialogOpen} onOpenChange={setAddTimeDialogOpen} onSave={(mins) => {
                const minute = Math.floor(time / 60) + 1;
                addEvent(null, 'add_time', minute, null, { added_minutes: mins }, `+${mins} min`);
                setAddTimeDialogOpen(false);
            }} />
        </div>
    );
}

"use client";

import { useState, useMemo } from "react";
import Image from "next/image";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { Team } from "@/types/index";
import { useTranslations } from "next-intl";
import { Trophy, AlertCircle, CheckCircle2, Users, ImageIcon, X, Upload, User, FileText, Loader2, Smartphone } from "lucide-react";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";

import { Button } from "@/components/ui/button";
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { PromptPayQR } from "./promptpay-qr";
import { registerTeam } from "@/actions/manager/register-team";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Separator } from "@/components/ui/separator";

// Schema generator based on fee
const createFormSchema = (isFree: boolean, t: any) => z.object({
    teamName: z.string().min(2, t("team_name_error")),
    contactName: z.string().min(2, t("contact_name_error")),
    contactPhone: z.string().min(10, t("contact_phone_error")),
    description: z.string().optional(),
    logoFile: z.any()
        .optional()
        .refine(
            (files) => !files || files.length === 0 || files[0].size <= 5 * 1024 * 1024,
            t("logo_size_error")
        )
        .refine(
            (files) => !files || files.length === 0 || ["image/jpeg", "image/png", "image/webp"].includes(files[0].type),
            t("logo_type_error")
        ),
    slipFile: isFree
        ? z.any().optional()
        : z.any()
            .refine((files) => files?.length === 1, t("slip_required"))
            .refine(
                (files) => files?.[0]?.size <= 5 * 1024 * 1024,
                t("slip_size_error")
            )
            .refine(
                (files) => ["image/jpeg", "image/png", "image/webp"].includes(files?.[0]?.type),
                t("slip_type_error")
            ),
});

interface RegistrationFormProps {
    tournament: {
        id: string;
        name: string;
        registration_fee: number;
        bank_account_number: string;
        bank_name: string;
        bank_account_name: string;
        is_registration_open: boolean;
        status: string;
    };
    initialTeams?: Team[];
}

export function RegistrationForm({ tournament, initialTeams }: RegistrationFormProps) {
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [success, setSuccess] = useState(false);
    const [logoPreviewUrl, setLogoPreviewUrl] = useState<string | null>(null);
    const [slipPreviewUrl, setSlipPreviewUrl] = useState<string | null>(null);
    const [selectedTeamId, setSelectedTeamId] = useState<string>("");

    const t = useTranslations("Registration");
    const isFree = Number(tournament.registration_fee) <= 0;
    const formSchema = useMemo(() => createFormSchema(isFree, t), [isFree, t]);

    const form = useForm<z.infer<typeof formSchema>>({
        resolver: zodResolver(formSchema),
        defaultValues: {
            teamName: "",
            contactName: "",
            contactPhone: "",
            description: "",
        },
    });

    const handleSelectTeam = (teamId: string) => {
        setSelectedTeamId(teamId);
        if (teamId === "new") {
            form.setValue("teamName", "");
            setLogoPreviewUrl(null);
            return;
        }

        const selectedTeam = initialTeams?.find(t => t.id === teamId);
        if (selectedTeam) {
            form.setValue("teamName", selectedTeam.name);
            form.setValue("description", selectedTeam.description || "");
            setLogoPreviewUrl(selectedTeam.logo_url || null);
        }
    };

    async function onSubmit(values: z.infer<typeof formSchema>) {
        setIsSubmitting(true);
        try {
            const formData = new FormData();
            formData.append("tournamentId", tournament.id);
            formData.append("teamName", values.teamName);
            formData.append("contactName", values.contactName);
            formData.append("contactPhone", values.contactPhone);
            if (values.description) {
                formData.append("description", values.description);
            }
            if (selectedTeamId && selectedTeamId !== "new") {
                formData.append("existingTeamId", selectedTeamId);
            }
            if (values.logoFile?.[0]) {
                formData.append("logoFile", values.logoFile[0]);
            } else if (logoPreviewUrl && !logoPreviewUrl.startsWith('data:')) {
                formData.append("logoUrl", logoPreviewUrl);
            }

            if (!isFree && values.slipFile?.[0]) {
                formData.append("slipFile", values.slipFile[0]);
            }

            const result = await registerTeam(formData);

            if (result.success) {
                setSuccess(true);
                toast.success(result.message || t("reg_success_toast"));
            } else {
                toast.error(result.error || t("reg_failed_toast"));
            }
        } catch (error) {
            toast.error("An unexpected error occurred");
            console.error(error);
        } finally {
            setIsSubmitting(false);
        }
    }

    if (success) {
        return (
            <div className="flex flex-col items-center justify-center py-12 text-center">
                <div className="w-16 h-16 bg-green-100 flex items-center justify-center mb-6">
                    <CheckCircle2 className="w-8 h-8 text-green-600" />
                </div>
                <h2 className="text-3xl font-bold text-gray-900 mb-2">{t("success_title")}</h2>
                <p className="text-muted-foreground max-w-md mb-8">
                    {t("success_desc")} {!isFree && t("success_desc_paid")}
                </p>
                <div className="flex gap-4">
                    <Button variant="outline" onClick={() => window.location.reload()}>
                        {t("register_another")}
                    </Button>
                    <Button onClick={() => window.location.href = `/manager/tournaments`}>
                        {t("go_to_dashboard")}
                    </Button>
                </div>
