                                        </div>
                                        <div className="flex justify-between items-center pt-1">
                                            <span className="text-[10px] font-black italic tracking-widest text-muted-foreground/40">{t("account_no_label")}</span>
                                            <span className="font-mono font-bold text-secondary text-lg leading-none tracking-tighter">{tournament.bank_account_number || "-"}</span>
                                        </div>
                                    </div>

                                    <FormField
                                        control={form.control}
                                        name="slipFile"
                                        render={({ field: { onChange, value: _value, ...rest } }) => (
                                            <FormItem className="flex-1 flex flex-col">
