                                                <FormControl className="flex-1">
                                                    <div className="group relative h-full flex flex-col">
                                                        {!slipPreviewUrl ? (
                                                            <div className="border-2 border-dashed border-muted-foreground/25 hover:border-primary/50 transition-colors p-12 py-20 text-center cursor-pointer bg-muted/5 hover:bg-muted/10 relative flex-1 flex items-center justify-center min-h-[300px]">
                                                                <Input
                                                                    type="file"
                                                                    accept="image/jpeg,image/png,image/webp"
                                                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                                                                    onChange={(e) => {
                                                                        const file = e.target.files?.[0];
                                                                        if (file) {
                                                                            onChange(e.target.files);
                                                                            setSlipPreviewUrl(URL.createObjectURL(file));
                                                                        }
                                                                    }}
                                                                    {...rest}
                                                                />
                                                                <div className="flex flex-col items-center gap-4">
