                                                                <div className="flex flex-col gap-4">
                                                                    <div className="relative aspect-[3/4] w-full max-h-[400px] overflow-hidden border bg-foreground flex items-center justify-center">
                                                                        <Image
                                                                            src={slipPreviewUrl}
                                                                            alt="Slip preview"
                                                                            width={300}
                                                                            height={400}
                                                                            className="object-contain w-full h-full"
                                                                            unoptimized
                                                                        />
                                                                        <Button
                                                                            type="button"
                                                                            variant="destructive"
                                                                            size="icon"
                                                                            className="absolute top-2 right-2 h-8 w-8 shadow-md"
                                                                            onClick={() => {
                                                                                onChange(undefined);
                                                                                setSlipPreviewUrl(null);
                                                                            }}
                                                                        >
                                                                            <X className="w-4 h-4" />
                                                                        </Button>
                                                                    </div>
                                                                    <div className="flex items-center justify-between">
                                                                        <div className="flex-1 min-w-0">
                                                                            <p className="text-sm font-semibold truncate text-foreground">{t("slip_preview")}</p>
                                                                            <p className="text-xs text-muted-foreground">{t("ready_to_submit")}</p>
                                                                        </div>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </div>
                                                </FormControl>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />
                                </div>
                            </div>
                        </div>
                    </>
                )}

                <div className="pt-4">
                    <Button
                        type="submit"
                        disabled={isSubmitting || isRegistrationClosed}
                        className="w-full h-12 text-base font-semibold shadow-md active:scale-[0.99] transition-all"
                        size="lg"
                        variant={isRegistrationClosed ? "secondary" : "default"}
                    >
                        {isSubmitting ? (
                            <>
                                <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                                {isFree ? t("registering") : t("verifying_registering")}
                            </>
                        ) : isRegistrationClosed ? (
                            t("registration_closed_title")
                        ) : (
                            isFree ? t("confirm_registration") : t("confirm_and_pay")
                        )}
                    </Button>
                    <p className="text-center text-xs text-muted-foreground mt-4">
                        {isFree
                            ? t("terms_free")
                            : t("terms_paid")}
                    </p>
                </div>
            </form>
        </Form>
    );
}

'use client'

import { useState } from "react"
import { generateFixtures } from "@/actions/organizer/tournaments/general"
import { Button } from "@/components/ui/button"
import { Wand2 } from "lucide-react"
import { useTranslations } from "next-intl"
import { cn } from "@/lib/utils"

export function FixtureGenerator({ 
  tournamentId, 
  hasFixtures, 
  format,
  className 
}: { 
  tournamentId: string, 
  hasFixtures: boolean, 
  format?: string,
  className?: string 
}) {
  const t = useTranslations("Fixtures")
  const [isLoading, setIsLoading] = useState(false)

  const isKnockout = format === 'knockout' || format === 'group_knockout';

  const getButtonText = () => {
    if (isLoading) return t("generating");
    if (!hasFixtures) return t("generate_fixtures");
    if (format === 'knockout') return "Refill Bracket";
    return "Regenerate";
  };

  const handleGenerate = async () => {
    let confirmMsg = t("confirm_generate");
    if (hasFixtures) {
      if (format === 'knockout') confirmMsg = "This will refill the bracket with actual teams. Continue?";
      else confirmMsg = "This will delete current scheduled fixtures and shuffle teams to generate a new schedule. Continue?";
    }
    const confirmPopup = window.confirm(confirmMsg)
    if (!confirmPopup) return

    setIsLoading(true)
    try {
      const result = await generateFixtures(tournamentId)
      if (!result.success && result.error) {
        alert(result.error)
      }
    } catch (e) {
      console.error(e)
      alert("An unexpected error occurred.")
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <Button 
      onClick={handleGenerate} 
      disabled={isLoading} 
      variant="ghost"
      className={cn(
        "w-full h-12 border border-foreground/5 font-black italic tracking-tighter transition-all duration-300 group overflow-hidden relative",
        hasFixtures ? "bg-foreground/5 hover:bg-foreground/10 text-muted-foreground/60 hover:text-foreground" : "bg-secondary text-secondary-foreground hover:bg-secondary/90 shadow-lg shadow-secondary/10",
        className
      )}
    >
      {!hasFixtures && <div className="absolute inset-0 bg-foreground/20 translate-y-full group-hover:translate-y-0 transition-transform duration-500" />}
      <Wand2 className={cn("mr-2 h-4 w-4 relative z-10", !hasFixtures && "animate-pulse")} />
      <span className="relative z-10">{getButtonText()}</span>
    </Button>
  )
}

"use client";

import { Match } from "@/types/index";
import { useState, useMemo } from "react";
import { useTranslations } from "next-intl";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";

interface FixturesCalendarProps {
    matches: Match[];
}

export function FixturesCalendar({ matches }: FixturesCalendarProps) {
    const t = useTranslations("Common");

    // Find initial month from matches or use current
    const initialDate = useMemo(() => {
        const matchWithDate = matches.find(m => m.match_date);
        if (matchWithDate?.match_date) {
            return new Date(matchWithDate.match_date);
        }
        return new Date();
    }, [matches]);

    const [currentMonth, setCurrentMonth] = useState(initialDate.getMonth());
    const [currentYear, setCurrentYear] = useState(initialDate.getFullYear());

    const daysInMonth = new Date(currentYear, currentMonth + 1, 0).getDate();
    const firstDayOfMonth = new Date(currentYear, currentMonth, 1).getDay();

    const matchesByDate = useMemo(() => {
        const map: Record<string, Match[]> = {};
        matches.forEach(match => {
            if (match.match_date) {
                const dateKey = match.match_date.split('T')[0];
                if (!map[dateKey]) map[dateKey] = [];
                map[dateKey].push(match);
            }
        });
        return map;
    }, [matches]);

    const prevMonth = () => {
        if (currentMonth === 0) {
            setCurrentMonth(11);
            setCurrentYear(currentYear - 1);
        } else {
            setCurrentMonth(currentMonth - 1);
        }
    };

    const nextMonth = () => {
        if (currentMonth === 11) {
            setCurrentMonth(0);
            setCurrentYear(currentYear + 1);
        } else {
            setCurrentMonth(currentMonth + 1);
        }
    };

    const monthName = new Date(currentYear, currentMonth).toLocaleString('default', { month: 'long', year: 'numeric' });

    const days = [];
    // Add empty cells for days before the first day
    for (let i = 0; i < firstDayOfMonth; i++) {
        days.push(null);
    }
    for (let d = 1; d <= daysInMonth; d++) {
        days.push(d);
    }

    return (
        <div className="space-y-4">
            {/* Header */}
            <div className="flex items-center justify-between">
                <Button variant="outline" size="icon" onClick={prevMonth}>
                    <ChevronLeft className="h-4 w-4" />
                </Button>
                <h3 className="font-semibold text-lg">{monthName}</h3>
                <Button variant="outline" size="icon" onClick={nextMonth}>
                    <ChevronRight className="h-4 w-4" />
                </Button>
            </div>

            {/* Day Headers */}
            <div className="grid grid-cols-7 gap-1">
                {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
                    <div key={day} className="text-center text-xs font-medium text-muted-foreground py-2">
                        {day}
                    </div>
                ))}
            </div>

            {/* Calendar Grid */}
            <div className="grid grid-cols-7 gap-1">
                {days.map((day, idx) => {
                    if (day === null) {
                        return <div key={`empty-${idx}`} className="min-h-[80px]" />;
                    }
                    const dateStr = `${currentYear}-${String(currentMonth + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                    const dayMatches = matchesByDate[dateStr] || [];
                    const isToday = new Date().toISOString().split('T')[0] === dateStr;

                    return (
                        <div
                            key={day}
                            className={cn(
                                "min-h-[80px] p-1 border text-xs",
                                isToday && "border-primary bg-primary/5",
                                dayMatches.length > 0 && "bg-muted/30"
                            )}
                        >
                            <span className={cn(
                                "font-medium text-xs",
                                isToday && "text-primary font-bold"
                            )}>
                                {day}
                            </span>
                            <div className="mt-1 space-y-0.5">
                                {dayMatches.slice(0, 3).map(match => (
                                    <div
                                        key={match.id}
                                        className={cn(
                                            "px-1 py-0.5 text-[10px] truncate",
                                            match.status === 'live' && "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400",
                                            match.status === 'finished' && "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400",
                                            match.status === 'scheduled' && "bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400"
                                        )}
                                    >
                                        {match.home_team?.name?.slice(0, 3) || '?'} vs {match.away_team?.name?.slice(0, 3) || '?'}
                                        {match.status === 'finished' && ` ${match.home_score}-${match.away_score}`}
                                    </div>
                                ))}
                                {dayMatches.length > 3 && (
                                    <Badge variant="outline" className="text-[9px] h-4 w-full justify-center">
                                        +{dayMatches.length - 3} more
                                    </Badge>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* Matches with no date */}
            {matches.filter(m => !m.match_date).length > 0 && (
                <div className="text-xs text-muted-foreground text-center py-2 border-t">
                    {matches.filter(m => !m.match_date).length} match(es) have no scheduled date
                </div>
            )}
        </div>
    );
}

"use client";

import { Match, Team } from "@/types/index";
import { StandingsTable } from "./standings-table";
import { calculateStandings } from "@/lib/standings";
import { useTranslations } from "next-intl";

interface GroupStandingsProps {
    teams: Team[];
    matches: Match[];
    isPublic?: boolean;
}

export function GroupStandings({ teams, matches, isPublic = false }: GroupStandingsProps) {
    // 1. Group teams by group_name
    const teamsByGroup = teams.reduce((acc, team) => {
        const group = team.group_name || "Unassigned";
        if (!acc[group]) acc[group] = [];
        acc[group].push(team);
        return acc;
    }, {} as Record<string, Team[]>);

    // Sort group names (A, B, C...)
    const sortedGroups = Object.keys(teamsByGroup).sort();

    const t = useTranslations("Tournament");

    return (
        <div className="space-y-4 md:space-y-6">
            <div id="group-standings-canvas" className="grid grid-cols-1 xl:grid-cols-2 gap-4 md:gap-6">
                {sortedGroups.map((group) => {
                    const groupTeams = teamsByGroup[group];
                    // Filter matches relevant to this group
                    const groupMatches = matches.filter(m => {
                        const groupTeamIds = new Set(groupTeams.map(t => t.id));
                        return m.stage === 'group' && (groupTeamIds.has(m.home_team_id || "") || groupTeamIds.has(m.away_team_id || ""));
                    });

                    // Calculate standings
                    const groupStandings = calculateStandings(groupTeams, groupMatches);

                    return (
                        <div key={group} className="space-y-4 md:space-y-6">
                            <div className="flex flex-col gap-1">
                                <h3 className="text-xl font-black italic tracking-tighter text-foreground flex items-center gap-3 relative z-10">
                                    <span className="w-2 h-2 bg-secondary shadow-[0_0_10px_rgba(0,196,154,0.4)]" />
                                    {t("group_header", { group })}
                                </h3>
                                <p className="text-[10px] font-bold text-muted-foreground/60">Group Stage Standings</p>
                            </div>
                            
                            <div className="bg-background border border-border/10 relative overflow-hidden transition-colors shadow-xl shadow-black/20">
                                <div className="absolute top-0 left-0 z-30 w-1 h-full bg-secondary" />
                                <div className="p-0">
                                    <StandingsTable standings={groupStandings} />
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { formatDate } from "@/lib/date";
import Image from "next/image";
import { useLocale, useTranslations } from "next-intl";
import { useSearchParams } from "next/navigation";
import { Eraser, ChevronRight } from "lucide-react";
import { Match, Goal, Team, MatchEvent } from "@/types/index";
import { updateMatch } from "@/actions/organizer/tournaments/general";
import { Button } from "@/components/ui/button";

import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { cn } from "@/lib/utils";
import { Link } from "@/i18n/routing";
import { createClient } from "@/lib/supabase/client";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";

// ...

export function MatchCard({ match: initialMatch, tournamentId, isPublic = false, isEditMode = false, teams = [] }: { match: Match; tournamentId: string; isPublic?: boolean; isEditMode?: boolean; teams?: Team[] }) {
    const t = useTranslations("Fixtures");
    const tMatch = useTranslations("Match");
    const tCommon = useTranslations("Common");
    const locale = useLocale();
    const searchParams = useSearchParams();

    const [isLoading, setIsLoading] = useState(false);
    const [clearDialogOpen, setClearDialogOpen] = useState(false);

    // --- Realtime Sync State ---
    const [match, setMatchState] = useState<Match>(initialMatch);

    // Update local state if prop changes
    useEffect(() => {
        setMatchState(initialMatch);
    }, [initialMatch]);

    // Supabase Realtime Subscription
    useEffect(() => {
        const supabase = createClient();
        const channel = supabase
            .channel(`match-card-${match.id}`)
            .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'matches', filter: `id=eq.${match.id}` }, (payload) => {
                setMatchState(payload.new as Match);
                // No router.refresh() here to avoid full page reloads on every card update, local state is enough for the card itself
            })
            .subscribe();

        return () => { supabase.removeChannel(channel); };
    }, [match.id]);

    // Local state for auto-save inputs
    const [matchDate, setMatchDate] = useState(match.match_date || "");
    const [matchTime, setMatchTime] = useState(match.match_time || "");

    const handleDateUpdate = async (newDate: string) => {
        setMatchDate(newDate);
        if (newDate !== match.match_date) {
            await updateMatch(match.id, { match_date: newDate }, tournamentId);
        }
    };

    const handleTimeUpdate = async (newTime: string) => {
        setMatchTime(newTime);
        if (newTime !== match.match_time) {
            await updateMatch(match.id, { match_time: newTime }, tournamentId);
        }
    };

    // Helper Variables
    const status = match.status?.toLowerCase() || 'scheduled';
    const isLive = status === 'live';
    const isFinished = status === 'finished';
    const isTie = isFinished && (match.home_score === match.away_score);

    // Format Date Helper
    // Use global formatDate helper
    // const formatDate = ... (removed)

    // Format Time Helper (24H)
    const formatTime = (timeStr?: string | null) => {
        if (!timeStr) return null;
        // Assume timeStr is HH:mm:ss or HH:mm
        const [h, m] = timeStr.split(':');
        return `${h.padStart(2, '0')}:${m}`;
    };

    // Tie Breaker Logic (ถ้าต้องการให้เลือกผู้ชนะเมื่อเสมอในรอบ Knockout)
    // const showTieBreaker = ... (removed as unused)

    const handleClear = async () => {
        setClearDialogOpen(false);
        setIsLoading(true);
        try {
            await updateMatch(match.id, {
                home_team_id: null,
                away_team_id: null,
                home_score: null,
                away_score: null,
                winner_id: null,
                status: 'scheduled'
            }, tournamentId);
        } catch (error) {
            console.error("Failed to clear match");
        } finally {
            setIsLoading(false);
        }
    };

    const CardContent = (
        <div
            className={cn(
                "flex flex-col md:grid md:grid-cols-[160px_1fr_120px] items-center px-4 md:px-6 py-2 md:py-4 transition-all cursor-pointer group relative overflow-hidden",
                isFinished ? "bg-[#050505]/60" : "bg-transparent hover:bg-foreground/5",
                "gap-4",
                isLive && "bg-secondary/5"
            )}
        >
            {/* Live Indicator Bar */}
            {isLive && <div className="absolute left-0 top-0 bottom-0 w-1 bg-secondary animate-pulse" />}

            {/* 1. Status/Time/Badge Section */}
            <div className="flex flex-col items-center justify-center w-full md:w-auto md:items-start md:justify-start gap-2 min-w-[120px]">
                {status !== 'scheduled' && (
                    <div
                        className={cn(
                            "text-[9px] tracking-[0.2em] font-black px-3 py-1 border-l-2",
                            status === 'scheduled' && "text-muted-foreground/40 border-muted-foreground/20",
                            isLive && "text-secondary border-secondary animate-pulse",
                            isFinished && "text-muted-foreground/60 border-muted-foreground/30",
                            !match.away_team_id && "text-muted-foreground/40 border-muted-foreground/20"
                        )}
                    >
                        {!match.away_team_id ? t("scheduled") : (
                            isLive ? (
                                <span className="flex items-center gap-2">
                                    <span className="relative flex h-1.5 w-1.5">
                                        <span className="animate-ping absolute inline-flex h-full w-full bg-secondary opacity-75"></span>
                                        <span className="relative inline-flex h-1.5 w-1.5 bg-secondary"></span>
                                    </span>
                                    {match.current_minute ? (
                                        typeof match.current_minute === 'number' ? `${match.current_minute}'` : match.current_minute
                                    ) : t("live")}
                                </span>
                            ) : (
                                isFinished ? t("ft") : t("scheduled")
                            )
                        )}
                    </div>
                )}

                {/* Date/Time Info (Edit Mode only) */}
                {!isFinished && !isLive && !isPublic && isEditMode && (
                    <div className="w-full">
                        <div className="flex flex-col gap-2 w-full" onClick={(e) => e.stopPropagation()}>
                            <Input
                                type="date"
                                className="h-8 bg-[#0A0A0A] border-foreground/5 text-[10px] font-black italic tracking-tighter"
                                value={matchDate}
                                onChange={(e) => handleDateUpdate(e.target.value)}
                            />
                            <Input
                                type="time"
                                className="h-8 bg-[#0A0A0A] border-foreground/5 text-[10px] font-black italic tracking-tighter"
                                value={formatTime(matchTime) || ""}
                                onChange={(e) => handleTimeUpdate(e.target.value)}
                            />
                        </div>
                    </div>
                )}
            </div>

            {/* 2. Teams & Score Section */}
            <div className="flex flex-row items-center justify-between w-full gap-4 md:gap-8">

                {/* Home Team */}
                <div className="flex-1 flex items-center justify-end gap-3 md:gap-6 text-right w-[40%]">
                    <div className={cn(
                        "text-base md:text-2xl font-black italic tracking-tighter flex items-center gap-3 justify-end group-hover:text-secondary transition-colors duration-300",
                        (isFinished && (match.home_score ?? -1) > (match.away_score ?? -1)) || match.winner_id === match.home_team_id ? "text-foreground" : "text-muted-foreground/60"
                    )}>
                        {isEditMode ? (
                            <div onClick={e => e.stopPropagation()}>
                                <Select
                                    value={match.home_team_id || "tbd"}
                                    onValueChange={(value) => updateMatch(match.id, { home_team_id: value === "tbd" ? "" : value }, tournamentId)}
                                >
                                    <SelectTrigger className="h-10 w-[120px] md:w-[180px] bg-[#0A0A0A] border-foreground/5 focus:ring-secondary/50 font-black italic tracking-tighter text-xs">
                                        <SelectValue placeholder={tMatch("select_team")} />
                                    </SelectTrigger>
                                    <SelectContent className="bg-[#111] border-foreground/5">
                                        <SelectItem value="tbd" className="font-black italic text-xs">{tMatch("tbd")}</SelectItem>
                                        {teams.map((t) => (
                                            <SelectItem key={t.id} value={t.id} className="font-black italic text-xs">{t.name}</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>
                        ) : (
                            <>
                                <span className={cn(
                                    "line-clamp-1 py-1 px-2 text-foreground",
                                    (isFinished && (match.home_score ?? -1) > (match.away_score ?? -1)) && "bg-secondary/10"
                                )}>
                                    {match.home_team?.name || tMatch("tbd")}
                                </span>
                                {match.home_team?.logo_url ? (
                                    <Image src={match.home_team.logo_url} width={48} height={48} className="w-8 h-8 md:w-12 md:h-12 object-contain grayscale-[0.2] group-hover:grayscale-0 transition-all" alt="" unoptimized />
                                ) : (
                                    <div className="w-8 h-8 md:w-12 md:h-12 bg-foreground/5 flex items-center justify-center shrink-0 border border-foreground/5">
                                        <span className="text-[10px] md:text-xs font-black text-muted-foreground/40">
                                            {match.home_team?.name?.substring(0, 2).toUpperCase() || "?"}
                                        </span>
                                    </div>
                                )}
                            </>
                        )}
                    </div>
                </div>

                {/* Score Box */}
                <div className="flex items-center justify-center shrink-0">
                    <div className={cn(
                        "flex flex-col items-center justify-center transition-all duration-300",
                        isLive ? " text-secondary-foreground scale-110" : 
                        isFinished ? " text-foreground" : " text-muted-foreground/40"
                    )}>
                        {isLive || isFinished ? (
                            <div className="flex flex-col w-[5rem] items-center leading-none">
                                <div className="flex items-center gap-1 md:gap-3">
                                    <span className="text-xl md:text-3xl font-black text-foreground italic tracking-tighter">
                                        {match.home_score ?? 0}
                                    </span>
                                    <span className="text-muted-foreground/20 font-black italic">-</span>
                                    <span className="text-xl md:text-3xl font-black text-foreground italic tracking-tighter">
                                        {match.away_score ?? 0}
                                    </span>
                                </div>
                                {((match.penalty_home_score ?? 0) > 0 || (match.penalty_away_score ?? 0) > 0) && (
                                    <span className="text-[8px] font-black tracking-tighter mt-1 opacity-60 italic">
                                        ({match.penalty_home_score ?? 0}-{match.penalty_away_score ?? 0} PK)
                                    </span>
                                )}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center min-w-[5rem] group-hover:scale-110 transition-transform duration-300">
                                <span className="text-lg md:text-xl font-black text-foreground italic tracking-tighter leading-none hover:text-secondary transition-colors">
                                    {formatTime(match.match_time) || "--:--"}
                                </span>
                                {match.match_date && (
                                    <span className="text-[9px] font-bold text-muted-foreground/40 tracking-[0.1em] mt-1 leading-none">
                                        {formatDate(match.match_date, "d MMM", locale)}
                                    </span>
                                )}
                            </div>
                        )}
                    </div>
                </div>

                {/* Away Team */}
                <div className="flex-1 flex items-center justify-start gap-3 md:gap-6 text-left w-[40%]">
                    <div className={cn(
                        "text-base md:text-2xl font-black italic tracking-tighter flex items-center gap-3 justify-start group-hover:text-secondary transition-colors duration-300",
                        (isFinished && (match.away_score ?? -1) > (match.home_score ?? -1)) || match.winner_id === match.away_team_id ? "text-foreground" : "text-muted-foreground/60"
                    )}>
                        {isEditMode ? (
                            <div onClick={e => e.stopPropagation()}>
                                <Select
                                    value={match.away_team_id || "tbd"}
                                    onValueChange={(value) => updateMatch(match.id, { away_team_id: value === "tbd" ? "" : value }, tournamentId)}
                                >
                                    <SelectTrigger className="h-10 w-[120px] md:w-[180px] bg-[#0A0A0A] border-foreground/5 focus:ring-secondary/50 font-black italic tracking-tighter text-xs">
                                        <SelectValue placeholder={tMatch("select_team")} />
                                    </SelectTrigger>
                                    <SelectContent className="bg-[#111] border-foreground/5">
                                        <SelectItem value="tbd" className="font-black italic text-xs">{tMatch("tbd")}</SelectItem>
                                        {teams.map((t) => (
                                            <SelectItem key={t.id} value={t.id} className="font-black italic text-xs">{t.name}</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>
                        ) : (
                            <>
                                {match.away_team?.logo_url ? (
                                    <Image src={match.away_team.logo_url} width={48} height={48} className="w-8 h-8 md:w-12 md:h-12 object-contain grayscale-[0.2] group-hover:grayscale-0 transition-all" alt="" unoptimized />
                                ) : (
                                    <div className="w-8 h-8 md:w-12 md:h-12 bg-foreground/5 flex items-center justify-center shrink-0 border border-foreground/5">
                                        <span className="text-[10px] md:text-xs font-black text-muted-foreground/40">
                                            {match.away_team?.name?.substring(0, 2).toUpperCase() || "?"}
                                        </span>
                                    </div>
                                )}
                                <span className={cn(
                                    "line-clamp-1 py-1 px-2 text-foreground",
                                    (isFinished && (match.away_score ?? -1) > (match.home_score ?? -1)) && "bg-secondary/10"
                                )}>
                                    {match.away_team?.name || tMatch("tbd")}
                                </span>
                            </>
                        )}
                    </div>
                </div>
            </div>

            {/* 3. Actions / Selection Indicator */}
            <div className="flex items-center justify-end md:ml-auto" onClick={e => e.stopPropagation()}>
                {isEditMode && match.away_team_id && (
                    <Button
                        size="icon"
                        variant="ghost"
                        className="h-10 w-10 text-muted-foreground/20 hover:text-destructive hover:bg-destructive/10 transition-colors"
                        onClick={() => setClearDialogOpen(true)}
                        disabled={isLoading}
                    >
                        <Eraser className="h-4 w-4" />
                    </Button>
                )}
                
                {/* Arrow indicator for drill-down */}
                <div className="mx-2 hidden md:block">
                    <ChevronRight className="h-4 w-4 text-muted-foreground/10 group-hover:text-secondary group-hover:translate-x-1 transition-all" />
                </div>
            </div>
        </div>
    );

    // If there is an away team, the card is clickable to open the full page console
    const canOpen = isPublic || !!match.away_team_id;
    const currentTab = searchParams.get('tab');
    const querySuffix = currentTab ? `?from=${currentTab}` : '';
    
    const url = isPublic 
        ? `/${tournamentId}/matches/${match.id}${querySuffix}`
        : `/organizer/tournaments/${tournamentId}/matches/${match.id}${querySuffix}`;

    return (
        <>
            {canOpen ? (
                <Link href={url} className="block transition-transform hover:scale-[1.01]">
                    {CardContent}
                </Link>
            ) : CardContent}

            <AlertDialog open={clearDialogOpen} onOpenChange={setClearDialogOpen}>
                <AlertDialogContent className="bg-card border-border/10 shadow-2xl max-w-md">
                    <AlertDialogHeader>
                        <AlertDialogTitle className="text-xl font-black italic tracking-tighter text-foreground flex items-center gap-2">
                            <Eraser className="h-5 w-5 text-destructive" />
                            {t("clear_match") || "Clear Match"}
                        </AlertDialogTitle>
                        <AlertDialogDescription className="text-sm font-medium text-muted-foreground/80 mt-2">
                            {t("confirm_clear")}
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter className="mt-6">
                        <AlertDialogCancel className="border-border/10 bg-foreground/5 hover:bg-foreground/10 hover:text-foreground transition-all h-10 text-[11px] font-black tracking-widest">
                            {tCommon("cancel")}
                        </AlertDialogCancel>
                        <AlertDialogAction
                            onClick={(e) => {
                                e.preventDefault();
                                handleClear();
                            }}
                            className="border border-destructive/20 bg-destructive/90 text-foreground hover:bg-destructive hover:shadow-[0_0_15_rgba(220,38,38,0.3)] transition-all h-10 text-[11px] font-black tracking-widest"
                        >
                            <Eraser className="h-3.5 w-3.5 mr-2" />
                            {t("clear") || "Clear"}
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { useTranslations } from "next-intl";
import { ActionResponse, Team, Match } from "@/types/index";
import { createMatch, updateMatch } from "@/actions/organizer/tournaments/general";
import { Loader2 } from "lucide-react";

interface MatchDialogProps {
    tournamentId: string;
    teams: Team[];
    match?: Match; // If provided, edit mode
    trigger?: React.ReactNode;
    defaultRound?: number;
    onSuccess?: () => void;
}

export function MatchDialog({ tournamentId, teams, match, trigger, defaultRound = 1, onSuccess }: MatchDialogProps) {
    const t = useTranslations("Match");
    const [open, setOpen] = useState(false);
    const [loading, setLoading] = useState(false);
    const [homeTeamId, setHomeTeamId] = useState<string>("");
    const [awayTeamId, setAwayTeamId] = useState<string>("");
    const [round, setRound] = useState<number>(defaultRound);

    // New Fields
    const [matchDate, setMatchDate] = useState<string>("");
    const [matchTime, setMatchTime] = useState<string>("");
    const [venue, setVenue] = useState<string>("");

    const isEdit = !!match;

    useEffect(() => {
        if (open) {
            if (match) {
                setHomeTeamId(match.home_team_id || "");
                setAwayTeamId(match.away_team_id || "");
                setRound(match.round);
                setMatchDate(match.match_date || "");
                setMatchTime(match.match_time || "");
                setVenue(match.venue || "");
            } else {
                setHomeTeamId("");
                setAwayTeamId("");
                setRound(defaultRound);
                setMatchDate("");
                setMatchTime("");
                setVenue("");
            }
        }
    }, [open, match, defaultRound]);

    // Format Time Helper
    const formatTime = (timeStr?: string | null) => {
        if (!timeStr) return "";
        const [h, m] = timeStr.split(':');
        return `${h.padStart(2, '0')}:${m}`;
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        try {
            let result: ActionResponse;

            if (isEdit && match) {
                result = await updateMatch(match.id, {
                    home_team_id: homeTeamId,
                    away_team_id: awayTeamId,
                    match_date: matchDate || null,
                    match_time: matchTime || null,
                    venue: venue || null
                }, tournamentId);
            } else {
                result = await createMatch(
                    tournamentId,
                    homeTeamId,
                    awayTeamId,
                    round,
                    'league', // Defaulting to league, might need to change if context provides stage
                    matchDate,
                    matchTime,
                    venue
                );
            }

            if (result.success) {
                setOpen(false);
                if (onSuccess) onSuccess();
            } else {
                alert(result.error);
            }
        } catch (error) {
            alert("An unexpected error occurred");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                {trigger || <Button variant="outline">{t("add_match")}</Button>}
            </DialogTrigger>
            <DialogContent>
                <DialogHeader>
                    <DialogTitle>{isEdit ? t("edit_match") : t("add_new_match")}</DialogTitle>
                    <DialogDescription>
                        {isEdit ? t("update_match_details") : t("schedule_new_match_manually")}
                    </DialogDescription>
                </DialogHeader>

                <form onSubmit={handleSubmit} className="grid gap-4 py-4">
                    <div className="grid grid-cols-4 items-center gap-4">
                        <Label className="text-right">{t("round")}</Label>
                        <Input
                            type="number"
                            value={round}
                            onChange={(e) => setRound(Number(e.target.value))}
                            className="col-span-3"
                            disabled={isEdit} // Usually we don't move rounds easily, but could enable if needed
                        />
                    </div>
                    <div className="grid grid-cols-4 items-center gap-4">
                        <Label className="text-right">{t("home")}</Label>
                        <Select value={homeTeamId} onValueChange={setHomeTeamId}>
                            <SelectTrigger className="col-span-3">
                                <SelectValue placeholder={t("select_home_team")} />
                            </SelectTrigger>
                            <SelectContent>
                                {teams.map((t) => (
                                    <SelectItem key={t.id} value={t.id} disabled={t.id === awayTeamId}>
                                        {t.name}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>
                    <div className="grid grid-cols-4 items-center gap-4">
                        <Label className="text-right">{t("away")}</Label>
                        <Select value={awayTeamId} onValueChange={setAwayTeamId}>
                            <SelectTrigger className="col-span-3">
                                <SelectValue placeholder={t("select_away_team")} />
                            </SelectTrigger>
                            <SelectContent>
                                {teams.map((t) => (
                                    <SelectItem key={t.id} value={t.id} disabled={t.id === homeTeamId}>
                                        {t.name}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="grid grid-cols-4 items-center gap-4">
                        <Label className="text-right">{t("date")}</Label>
                        <Input
                            type="date"
                            value={matchDate}
                            onChange={(e) => setMatchDate(e.target.value)}
                            className="col-span-3"
                        />
                    </div>

                    <div className="grid grid-cols-4 items-center gap-4">
                        <Label className="text-right">{t("time")}</Label>
                        <Input
                            type="time"
                            value={formatTime(matchTime)}
                            onChange={(e) => setMatchTime(e.target.value)}
                            className="col-span-3"
                        />
                    </div>

                    <div className="grid grid-cols-4 items-center gap-4">
                        <Label className="text-right">{t("location")}</Label>
                        <Input
                            placeholder={t("location")}
                            value={venue}
                            onChange={(e) => setVenue(e.target.value)}
                            className="col-span-3"
                        />
                    </div>

                    <DialogFooter>
                        <Button type="submit" disabled={loading || !homeTeamId || !awayTeamId}>
                            {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            {isEdit ? t("save") : t("create")}
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useState, useEffect, useMemo, useRef } from "react";
import { useTranslations, useLocale } from "next-intl";
import { Loader2, Calendar as CalendarIcon, ChevronLeft, ChevronRight, Trophy } from "lucide-react";
import { startOfDay, addDays, subDays, addMonths, subMonths, format, startOfMonth, endOfMonth, eachDayOfInterval, getDay } from "date-fns";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { MatchCard } from "./match-card";
import { getPublicMatches } from "@/actions/public/public-matches";
import { formatDate } from "@/lib/date";
import { Link } from "@/i18n/routing";
import { Match, Tournament } from "@/types";

type PublicMatch = Match & { tournaments: Tournament };

export function PublicMatchListHome() {
    const t = useTranslations("Home");
    const tPublic = useTranslations("PublicView");
    const locale = useLocale();
    const [matches, setMatches] = useState<PublicMatch[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    const [selectedDate, setSelectedDate] = useState<string | null>(() => {
        // Default to today's date in YYYY-MM-DD format
        return format(new Date(), 'yyyy-MM-dd');
    });

    // Extract all unique tournaments from matches
    const allTournaments = useMemo(() => {
        const unique = new Map();
        matches.forEach((m) => {
            if (m.tournaments && !unique.has(m.tournament_id)) {
                unique.set(m.tournament_id, {
                    id: m.tournament_id,
                    name: m.tournaments.name
                });
            }
        });
        return Array.from(unique.values()).sort((a, b) => a.name.localeCompare(b.name));
    }, [matches]);

    const selectedRef = useRef<HTMLButtonElement>(null);
    const [isCalendarOpen, setIsCalendarOpen] = useState(false);

    // Month for the calendar picker dropdown
    const [viewDate, setViewDate] = useState(new Date());

    useEffect(() => {
        const fetchMatches = async () => {
            setIsLoading(true);
            try {
                const data = await getPublicMatches();
                setMatches(data || []);
            } catch (error) {
                console.error("Failed to fetch matches:", error);
            } finally {
                setIsLoading(false);
            }
        };

        const timer = setTimeout(fetchMatches, 300);
        return () => clearTimeout(timer);
    }, []);

    // Scroll logic (less critical now without scroller, but useful for reference)
    useEffect(() => {
        if (selectedDate && selectedRef.current) {
            selectedRef.current.scrollIntoView({ behavior: 'smooth', inline: 'center', block: 'nearest' });
        }
    }, [selectedDate]);

    const goToPrevDay = () => {
        const current = selectedDate ? new Date(selectedDate) : new Date();
        const prev = subDays(current, 1);
        setSelectedDate(format(prev, 'yyyy-MM-dd'));
    };

    const goToNextDay = () => {
        const current = selectedDate ? new Date(selectedDate) : new Date();
        const next = addDays(current, 1);
        setSelectedDate(format(next, 'yyyy-MM-dd'));
    };

    // Calendar Grid Logic
    const calendarDays = useMemo(() => {
        const startOfViewMonth = startOfMonth(viewDate);
        const endOfViewMonth = endOfMonth(viewDate);
        const firstDay = getDay(startOfViewMonth);
        
        const days = [];
        for (let i = 0; i < firstDay; i++) days.push(null);
        
        const interval = eachDayOfInterval({ start: startOfViewMonth, end: endOfViewMonth });
        interval.forEach(day => days.push(day));
        
        return days;
    }, [viewDate]);

    const changeMonth = (offset: number) => {
        setViewDate(addDays(startOfMonth(viewDate), offset * 32)); // rough jump to next/prev month
    };

    // Generate date range (Today +/- 7 days)
    const dateRange = useMemo(() => {
        const today = startOfDay(new Date());
        return Array.from({ length: 15 }, (_, i) => {
            const date = addDays(subDays(today, 7), i);
            return format(date, 'yyyy-MM-dd');
        });
    }, []);

    // Set of dates that have matches for the dot indicator
    const datesWithMatches = useMemo(() => {
        return new Set(matches.map(m => m.match_date).filter(Boolean));
    }, [matches]);

    const filteredMatches = useMemo(() => {
        return matches.filter(m => {
            
            const matchesDate = !selectedDate || m.match_date === selectedDate;
            
            return matchesDate;
        });
    }, [matches, selectedDate]);

    // Group matches by date and tournament
    const groupedMatches = filteredMatches.reduce((acc: Record<string, Record<string, PublicMatch[]>>, match) => {
        const date = match.match_date || "TBD";
        const tournamentName = match.tournaments?.name || "Tournament";
        if (!acc[date]) acc[date] = {};
        if (!acc[date][tournamentName]) acc[date][tournamentName] = [];
        acc[date][tournamentName].push(match);
        return acc;
    }, {});

    const sortedDates = Object.keys(groupedMatches)
        .sort((a, b) => {
            if (a === "TBD") return 1;
            if (b === "TBD") return -1;
            return new Date(b).getTime() - new Date(a).getTime();
        });

    return (
        <div className="space-y-6">

            {/* Navigation Header */}
            {!isLoading && (
                <div className="flex flex-col sm:flex-row items-center gap-4 w-full">
                    <div className="flex items-center gap-1 bg-muted/5 border border-border/40 p-1 w-full">
                        <button
                            onClick={() => setSelectedDate(null)}
                            className={cn(
                                "px-6 py-2 text-xs font-black italic tracking-tighter transition-all shrink-0",
                                selectedDate === null 
                                    ? "bg-secondary text-secondary-foreground shadow-[0_0_15px_rgba(var(--secondary),0.3)]"
                                    : "text-muted-foreground/60 hover:text-secondary"
                            )}
                        >
                            {locale === 'th' ? "ทั้งหมด" : "ALL"}
                        </button>
                        
                        <div className="h-4 w-[1px] bg-border/40 mx-1 shrink-0" />

                        <div className="flex items-center flex-1">
                            <button
                                onClick={goToPrevDay}
                                className="p-3 hover:text-secondary text-muted-foreground/40 transition-colors shrink-0"
                            >
                                <ChevronLeft className="h-5 w-5" />
                            </button>

                            <Popover open={isCalendarOpen} onOpenChange={setIsCalendarOpen}>
                                <PopoverTrigger asChild>
                                    <button className="px-4 py-2 flex items-center justify-center gap-4 hover:bg-muted/10 transition-all border-x border-border/10 flex-1 min-h-[56px]">
                                        <CalendarIcon className="h-5 w-5 text-secondary animate-pulse shrink-0" />
                                        <div className="flex flex-col items-center">
                                            <span className="text-[10px] font-black italic tracking-tighter text-secondary leading-none mb-1">
                                                {selectedDate ? formatDate(selectedDate, "EEE", locale) : (locale === 'th' ? "วันนี้" : "TODAY")}
                                            </span>
                                            <span className="text-base font-black italic tracking-tight">
                                                {selectedDate ? formatDate(selectedDate, "d MMM yyyy", locale) : formatDate(new Date(), "d MMM yyyy", locale)}
                                            </span>
                                        </div>
                                    </button>
                                </PopoverTrigger>

                                <PopoverContent className="w-80 p-0 bg-background border-border/40 shadow-2xl" align="center">
                                    <div className="p-4 border-b border-border/40 flex items-center justify-between bg-muted/5">
                                        <button onClick={() => setViewDate(subMonths(viewDate, 1))} className="p-1 hover:text-secondary">
                                            <ChevronLeft className="h-4 w-4" />
                                        </button>
                                        <span className="text-sm font-black italic tracking-tighter">
                                            {viewDate.toLocaleString(locale === 'th' ? 'th-TH' : 'en-US', { month: 'long', year: 'numeric' })}
                                        </span>
                                        <button onClick={() => setViewDate(addMonths(viewDate, 1))} className="p-1 hover:text-secondary">
                                            <ChevronRight className="h-4 w-4" />
                                        </button>
                                    </div>
                                    <div className="p-4">
                                        <div className="grid grid-cols-7 gap-1 mb-2">
                                            {(locale === 'th' ? ['อา','จ','อ','พ','พฤ','ศ','ส'] : ['S','M','T','W','T','F','S']).map((d, idx) => (
                                                <div key={`${d}-${idx}`} className="text-[10px] text-center font-black opacity-30 italic">{d}</div>
                                            ))}
                                        </div>
                                        <div className="grid grid-cols-7 gap-1">
                                            {calendarDays.map((day, i) => {
                                                if (!day) return <div key={`empty-${i}`} />;
                                                const dateStr = format(day, 'yyyy-MM-dd');
                                                const isSel = selectedDate === dateStr;
                                                const hasMatch = datesWithMatches.has(dateStr);
                                                const isToday = dateStr === format(new Date(), 'yyyy-MM-dd');

                                                return (
                                                    <button
                                                        key={dateStr}
                                                        onClick={() => {
                                                            setSelectedDate(dateStr);
                                                            setIsCalendarOpen(false);
                                                        }}
                                                        className={cn(
                                                            "h-9 flex flex-col items-center justify-center relative transition-all",
                                                            isSel ? "bg-secondary text-secondary-foreground font-black" : "hover:bg-muted/10",
                                                            isToday && !isSel && "border border-secondary/30 text-secondary"
                                                        )}
                                                    >
                                                        <span className="text-xs">{format(day, 'd')}</span>
                                                        {hasMatch && (
                                                            <div className={cn(
                                                                "absolute bottom-1 h-1 w-1 rounded-full",
                                                                isSel ? "bg-secondary-foreground" : "bg-secondary"
                                                            )} />
                                                        )}
                                                    </button>
                                                );
                                            })}
                                        </div>
                                        <button
                                            onClick={() => {
                                                setSelectedDate(format(new Date(), 'yyyy-MM-dd'));
                                                setViewDate(new Date());
                                                setIsCalendarOpen(false);
                                            }}
                                            className="w-full mt-4 py-2 border border-border/40 text-[10px] font-black italic hover:border-secondary transition-all"
                                        >
                                            {locale === 'th' ? "กลับไปที่วันนี้" : "BACK TO TODAY"}
                                        </button>
                                    </div>
                                </PopoverContent>
                            </Popover>

                            <button
                                onClick={goToNextDay}
                                className="p-2 hover:text-secondary text-muted-foreground/40 transition-colors"
                            >
                                <ChevronRight className="h-5 w-5" />
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <div className="flex flex-col lg:flex-row gap-8 items-start">
                <div className="flex-1 w-full space-y-12">
                    {isLoading ? (
                        <div className="flex flex-col items-center justify-center py-24 gap-6 bg-muted/5 border border-dashed border-border/40 relative overflow-hidden group">
                            <div className="absolute inset-0 bg-secondary/5 opacity-0 group-hover:opacity-100 transition-opacity" />
                            <div className="relative">
                                <Loader2 className="h-12 w-12 animate-spin text-secondary relative z-10" />
                            </div>
                            <p className="text-secondary font-black italic tracking-[0.3em] text-xs animate-pulse relative z-10">{t("searching") || "LOADING MATCHES..."}</p>
                        </div>
                    ) : filteredMatches.length === 0 ? (
                        <div className="text-center py-24 border border-dashed border-border/40 bg-muted/5 relative overflow-hidden group">
                            <p className="text-4xl font-black italic tracking-tighter text-muted-foreground/10 mb-2">{t("no_results") || "NO MATCHES FOUND"}</p>
                            <Button 
                                variant="outline" 
                                onClick={() => {
                                    setSelectedDate(null);
                                }}
                                className="font-black italic tracking-tighter"
                            >
                                {locale === 'th' ? "ดูแมตช์ทั้งหมด" : "SEE ALL MATCHES"}
                            </Button>
                        </div>
                    ) : (
                        <div className="space-y-12">
                            {sortedDates.map(date => (
                                <div key={date} className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
                                    <div className="flex items-center gap-4 bg-muted/5 border-l-4 border-secondary p-4">
                                        <CalendarIcon className="h-6 w-6 text-secondary" />
                                        <h3 className="text-2xl font-black italic tracking-tighter">
                                            {date === "TBD" ? (locale === 'th' ? "รอกำหนดการ" : "To Be Determined") : formatDate(date, "EEEE, d MMM yyyy", locale)}
                                        </h3>
                                    </div>

                                    <div className="space-y-12 pl-4 sm:pl-8 border-l border-border/10">
                                        {Object.entries(groupedMatches[date]).map(([tournamentName, tournamentMatches]) => (
                                            <div key={tournamentName} className="space-y-6">
                                                <div className="flex items-center gap-3 group/tour">
                                                    <div className="h-8 w-1 bg-secondary/20 group-hover/tour:bg-secondary transition-all" />
                                                    <div className="flex flex-col">
                                                        <span className="text-[10px] font-black italic tracking-[0.2em] text-secondary/40 leading-none mb-1">TOURNAMENT</span>
                                                        <h4 className="text-lg font-black italic tracking-tight text-foreground group-hover/tour:text-secondary transition-colors">
                                                            {tournamentName}
                                                        </h4>
                                                    </div>
                                                    <div className="h-px flex-1 bg-gradient-to-r from-border/50 to-transparent ml-4" />
                                                </div>
                                                <div className="grid grid-cols-1 gap-4">
                                                    {tournamentMatches.map((match) => (
                                                        <MatchCard 
                                                            key={match.id} 
                                                            match={match} 
                                                            tournamentId={match.tournament_id}
                                                            isPublic={true}
                                                        />
                                                    ))}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {!isLoading && allTournaments.length > 0 && (
                    <div className="w-full lg:w-80 shrink-0 space-y-6">
                        <div className="bg-muted/5 border border-border/40 p-6 sticky top-24 backdrop-blur-sm">
                            <div className="flex items-center justify-between mb-6">
                                <div className="flex items-center gap-3">
                                    <Trophy className="h-6 w-6 text-secondary" />
                                    <h3 className="text-2xl font-black italic tracking-tighter">
                                        {locale === 'th' ? "รายการแข่ง" : "TOURNAMENTS"}
                                    </h3>
                                </div>
                            </div>

                            <div className="space-y-2">

                                {allTournaments.map((tournament) => (
                                    <Link
                                        key={tournament.id}
                                        href={`/${tournament.id}`}
                                        className="w-full text-left px-4 py-4 text-sm font-black italic tracking-tight transition-all relative group border-l-2 block border-transparent text-muted-foreground/40 hover:text-foreground hover:bg-muted/5"
                                    >
                                        <div className="flex items-center justify-between">
                                            <span className="truncate pr-4">{tournament.name}</span>
                                            <Trophy className="h-3 w-3 transition-all duration-300 scale-0 opacity-0 group-hover:scale-100 group-hover:opacity-40" />
                                        </div>
                                    </Link>
                                ))}
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

import { Link } from "@/i18n/routing";
import { cn } from "@/lib/utils";


import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { CalendarDays, Users, Trophy } from "lucide-react";
import { formatDate } from "@/lib/date";
import { useLocale, useTranslations } from "next-intl";

interface PublicTournamentCardProps {
    tournament: any;
    isManager?: boolean;
}

export function PublicTournamentCard({ tournament, isManager = false }: PublicTournamentCardProps) {
    const t = useTranslations("Common");
    const locale = useLocale();
    const tSettings = useTranslations("Settings");
    const tDashboard = useTranslations("Dashboard");

    // Assuming we want to show a PRO badge if the tournament is on a paid plan
    const isPro = tournament.plan && tournament.plan !== 'free';

    const currentTeams = tournament.tournament_teams?.[0]?.count || 0;
    const isFull = tournament.max_teams && currentTeams >= tournament.max_teams;
    const isPastDeadline = tournament.document_deadline && new Date(tournament.document_deadline) < new Date();
    const isClosed = isFull || isPastDeadline;

    return (
        <Link href={isManager ? `/manager/tournaments/${tournament.id}` : `/${tournament.id}`} className="block h-full group">
            <Card className="flex flex-col h-full bg-card pt-4 md:pt-6 pb-4 md:pb-5 border border-border transition-all hover:border-secondary/50 overflow-hidden relative shadow-lg cursor-pointer">
                <div className="absolute top-0 left-0 w-1 h-full bg-secondary" />
                <div className="absolute -right-4 -top-4 w-24 h-24 bg-secondary/5 rotate-12 transition-transform group-hover:scale-110" />
                {isPro && (
                    <div className="absolute right-6 z-20">
                        <div className="bg-secondary/10 text-secondary text-[8px] font-black px-2 py-0.5 tracking-[0.2em] border border-secondary/20 backdrop-blur-md">
                            {t("pro")}
                        </div>
                    </div>
                )}
                <CardHeader className="relative z-10">
                    <div className="flex flex-col gap-2">
                        <div className="flex items-center justify-between">
                            {tournament.status && tournament.status !== 'active' && (
                                <div className={cn("text-[9px] font-black tracking-widest px-2 py-0.5",
                                    tournament.status === 'completed' ? "bg-muted text-muted-foreground/40" : "bg-secondary/10 text-secondary border border-secondary/20"
                                )}>
                                    {tSettings(tournament.status as any)}
                                </div>
                            )}
                            {isClosed && (
                                <div className="text-[9px] font-black tracking-widest px-2 py-0.5 bg-red-500/10 text-red-600 border border-red-500/20 ml-2">
                                    {isFull ? (tSettings("full") || "FULL") : (tSettings("closed") || "CLOSED")}
                                </div>
                            )}
                            <div className="flex items-center gap-1.5 opacity-60">
                                <Trophy className="h-3 w-3 text-secondary" />
                                <span className="text-[9px] font-black italic tracking-tighter text-muted-foreground/80">{tournament.format || 'League'}</span>
                            </div>
                        </div>
                        <CardTitle className="text-2xl font-black leading-none tracking-tighter italic group-hover:text-secondary transition-colors truncate">
                            {tournament.name}
                        </CardTitle>
                    </div>
                </CardHeader>

                <CardContent className="relative z-10 px-6">
                    <div className="flex flex-col gap-4">
                        <div className="grid grid-cols-2 gap-4 border-t border-border/40 pt-4">
                            <div className="flex flex-col">
                                <span className="text-[8px] font-black text-muted-foreground/40 tracking-[0.2em] italic mb-1">{t("kick_off")}</span>
                                <div className="flex items-center gap-2">
                                    <CalendarDays className="h-3.5 w-3.5 text-secondary/40 shrink-0" />
                                    <span className="text-[11px] font-black tabular-nums tracking-tight">
                                        {tournament.start_date
                                            ? formatDate(tournament.start_date, "MMM d, yyyy", locale)
                                            : tDashboard("card_not_scheduled")}
                                    </span>
                                </div>
                            </div>
                            <div className="flex flex-col">
                                <span className="text-[8px] font-black text-muted-foreground/40 tracking-[0.2em] italic mb-1">{t("team_limit")}</span>
                                <div className="flex items-center gap-2">
                                    <Users className="h-3.5 w-3.5 text-secondary/40 shrink-0" />
                                    <span className="text-[11px] font-black tabular-nums tracking-tight">
                                        {tournament.max_teams ? `${currentTeams}/${tournament.max_teams} ${t("teams")}` : t("open")}
                                    </span>
                                </div>
                            </div>
                        </div>
                    </div>
                </CardContent>
            </Card>
        </Link>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useTranslations } from "next-intl";
import { Search, Loader2 } from "lucide-react";
import { Input } from "@/components/ui/input";
import { PublicTournamentCard } from "./public-tournament-card";
import { getPublicTournaments } from "@/actions/public/public-tournaments";

export function PublicTournamentList({ onlyActive = false, isManager = false }: { onlyActive?: boolean, isManager?: boolean }) {
    const t = useTranslations("Home");
    const [search, setSearch] = useState("");
    const [tournaments, setTournaments] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const fetchTournaments = async () => {
            setIsLoading(true);
            try {
                const data = await getPublicTournaments(search);
                setTournaments(data || []);
            } catch (error) {
                console.error("Failed to fetch tournaments:", error);
            } finally {
                setIsLoading(false);
            }
        };

        const timer = setTimeout(fetchTournaments, 300);
        return () => clearTimeout(timer);
    }, [search]);

    const activeTournaments = tournaments.filter(t => t.status === "active");
    const completedTournaments = tournaments.filter(t => t.status === "completed");

    return (
        <div className="space-y-4 md:space-y-6">
            <div className="relative max-w-2xl ml-0 group">
                <div className="relative">
                    <Search className="absolute left-5 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground/30 group-focus-within:text-secondary group-focus-within:scale-110 transition-all duration-300" />
                    <Input
                        placeholder={t("search_placeholder")}
                        className="pl-14 h-16 text-lg bg-muted/5 border-border/40 group-focus-within:border-secondary group-focus-within:bg-muted/10 transition-all duration-500 font-black italic tracking-tight placeholder:text-muted-foreground/20"
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                    />
                    <div className="absolute bottom-0 left-0 w-0 h-[2px] bg-secondary group-focus-within:w-full transition-all duration-700" />
                </div>
            </div>

            {isLoading ? (
                <div className="flex flex-col items-center justify-center py-24 gap-6 bg-muted/5 border border-dashed border-border/40 relative overflow-hidden group">
                    <div className="absolute inset-0 bg-secondary/5 opacity-0 group-hover:opacity-100 transition-opacity" />
                    <div className="relative">
                        <Loader2 className="h-12 w-12 animate-spin text-secondary relative z-10" />
                        <div className="absolute inset-x-0 bottom-0 h-4 bg-secondary/20 blur-xl animate-pulse" />
                    </div>
                    <p className="text-secondary font-black italic tracking-[0.3em] text-xs animate-pulse relative z-10">{t("searching")}</p>
                </div>
            ) : tournaments.length === 0 ? (
                <div className="text-center py-24 border border-dashed border-border/40 bg-muted/5 relative overflow-hidden group">
                    <div className="absolute top-0 left-0 w-full h-[2px] bg-muted/10" />
                    <div className="absolute -right-10 -bottom-10 h-40 w-40 bg-secondary/5 rotate-12 transition-transform group-hover:scale-110" />
                    <p className="text-4xl font-black italic tracking-tighter text-muted-foreground/10 mb-2">{t("no_results")}</p>
                    <p className="text-[10px] font-black tracking-widest text-muted-foreground/40">{t("try_adjusting_filters") || "Try adjusting your search query"}</p>
                </div>
            ) : (
                <div className="space-y-20">
                    {activeTournaments.length > 0 && (
                        <div className="space-y-8">
                            {!onlyActive && (
                                <div className="flex items-center gap-6 mb-12">
                                    <div className="h-4 w-4 bg-secondary shadow-[0_0_15px_rgba(0,196,154,0.4)]" />
                                    <h2 className="text-4xl font-black italic tracking-tighter text-foreground">{t("active_tournaments")}</h2>
                                    <div className="h-px flex-1 bg-gradient-to-r from-secondary/40 to-transparent" />
                                </div>
                            )}
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
                                {activeTournaments.map((tournament) => (
                                    <PublicTournamentCard key={tournament.id} tournament={tournament} isManager={isManager} />
                                ))}
                            </div>
                        </div>
                    )}

                    {!onlyActive && completedTournaments.length > 0 && (
                        <div className="space-y-4 md:space-y-6">
                            <div className="flex items-center gap-4 md:gap-6">
                                <h2 className="text-3xl font-black italic tracking-tighter text-muted-foreground/40">{t("completed_tournaments")}</h2>
                                <div className="h-px flex-1 bg-gradient-to-r from-border/50 to-transparent" />
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 grayscale opacity-60 hover:grayscale-0 hover:opacity-100 transition-all duration-700">
                                {completedTournaments.map((tournament) => (
                                    <PublicTournamentCard key={tournament.id} tournament={tournament} isManager={isManager} />
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

"use client";

import { useState, useEffect, useMemo } from "react";
import { Trophy, Users, Calendar, ArrowLeft, GitBranch, Award } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
