import { createClient } from "@/lib/supabase/client";
import { useTranslations } from "next-intl";
import { useRouter, usePathname, Link } from "@/i18n/routing";
import { useSearchParams } from "next/navigation";
import { cn } from "@/lib/utils";

import { TournamentStats } from "@/components/tournaments/tournament-stats";
import { PlayerStatsTable } from "@/components/tournaments/player-stats-table";
import { BannedPlayersCard } from "@/components/tournaments/banned-players-card";
import { TopScorersTable } from "@/components/tournaments/top-scorers-table";
import { calculatePlayerStats, getBannedPlayers } from "@/lib/player-stats";

interface PublicTournamentViewProps {
    tournament: Tournament;
    initialTeams: Team[];
    initialMatches: Match[];
    initialEvents: MatchEvent[];
    initialGoals: Goal[];
    initialPlayers: Player[];
}

export function PublicTournamentView({
    tournament: initialTournament,
    initialTeams,
    initialMatches,
    initialEvents,
    initialGoals,
    initialPlayers
}: PublicTournamentViewProps) {
    const t = useTranslations("PublicView");
    const tTournament = useTranslations("Tournament");
    const [matches, setMatches] = useState<Match[]>(initialMatches);
    const [events, setEvents] = useState<MatchEvent[]>(initialEvents);
    const [tournament, setTournament] = useState(initialTournament);
    const [goals, setGoals] = useState<Goal[]>(initialGoals || []);
    const router = useRouter();
    const pathname = usePathname();
    const searchParams = useSearchParams();

    const allPlayersForStats = useMemo(() => {
        return (initialPlayers || []).map(p => ({
            ...p,
            teamName: initialTeams.find(t => t.id === p.team_id)?.name,
            teamLogoUrl: initialTeams.find(t => t.id === p.team_id)?.logo_url
        }));
    }, [initialPlayers, initialTeams]);

    const playerStats = useMemo(() => {
        return calculatePlayerStats(events, allPlayersForStats, null);
    }, [allPlayersForStats, events]);

    const bannedPlayers = useMemo(() => {
        return getBannedPlayers(events, allPlayersForStats, null);
    }, [allPlayersForStats, events]);

    const standings = useMemo(() => {
        return calculateStandings(initialTeams, matches);
    }, [initialTeams, matches]);

    const currentTab = searchParams.get('tab') || 'overview';

    const handleTabChange = (value: string) => {
        const params = new URLSearchParams(searchParams.toString());
        if (value === 'overview') {
            params.delete('tab');
        } else {
            params.set('tab', value);
        }
        router.replace(`${pathname}?${params.toString()}`, { scroll: false });
    };

    useEffect(() => {
        const supabase = createClient();

        const tourneyChannel = supabase
            .channel(`public-tournament-${initialTournament.id}`)
            .on('postgres_changes', {
                event: 'UPDATE',
                schema: 'public',
                table: 'tournaments',
                filter: `id=eq.${initialTournament.id}`
            }, (payload) => {
                setTournament(payload.new);
            })
            .subscribe();

        const matchChannel = supabase
            .channel(`public-matches-${initialTournament.id}`)
            .on('postgres_changes', {
                event: '*',
                schema: 'public',
                table: 'matches',
                filter: `tournament_id=eq.${initialTournament.id}`
            }, (payload) => {
                if (payload.eventType === 'INSERT') {
                    setMatches(prev => [...prev, payload.new as Match]);
                } else if (payload.eventType === 'UPDATE') {
                    setMatches(prev => prev.map(m => m.id === payload.new.id ? { ...m, ...payload.new } : m));
                } else if (payload.eventType === 'DELETE') {
                    setMatches(prev => prev.filter(m => m.id !== payload.old.id));
                }
            })
            .subscribe();

        const eventChannel = supabase
            .channel(`public-events-${initialTournament.id}`)
            .on('postgres_changes', {
                event: '*',
                schema: 'public',
                table: 'match_events'
            }, (payload) => {
                const matchIds = matches.map(m => m.id);
                if (payload.new && !matchIds.includes((payload.new as MatchEvent).match_id)) return;
                if (payload.old && !matchIds.includes((payload.old as MatchEvent).match_id)) return;

                if (payload.eventType === 'INSERT') {
                    setEvents(prev => [payload.new as MatchEvent, ...prev]);
                } else if (payload.eventType === 'DELETE') {
                    setEvents(prev => prev.filter(e => e.id !== payload.old.id));
                } else if (payload.eventType === 'UPDATE') {
                    setEvents(prev => prev.map(e => e.id === payload.new.id ? { ...e, ...payload.new } : e));
                }
            })
            .subscribe();

        return () => {
            supabase.removeChannel(tourneyChannel);
            supabase.removeChannel(matchChannel);
            supabase.removeChannel(eventChannel);
        };
    }, [initialTournament.id, matches.length, matches]);

    return (
        <main className="container mx-auto px-2 md:px-0 py-6 max-w-6xl">
            {/* Unified Header Block - Pro Sports Style */}
            <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 md:gap-6 border-b-4 border-secondary/20 pb-4 md:pb-6 mb-4 md:mb-6 relative group">
                <div className="flex items-start gap-3 md:gap-6 w-full">
                    <Button
                        variant="ghost"
                        size="icon"
                        asChild
                        className="h-8 w-8 md:h-10 md:w-10 shrink-0 border border-foreground/10 bg-foreground/5 hover:bg-secondary hover:text-black transition-all shadow-xl shadow-black/40"
                    >
                        <Link href="/">
                            <ArrowLeft className="h-5 w-5 md:h-6 md:w-6" />
                        </Link>
                    </Button>

                    <div className="flex flex-col flex-1 gap-1 md:gap-2 min-w-0">
                        {/* Metadata Badges */}
                        <div className="flex flex-wrap items-center gap-2 mb-1">
                            <Badge variant="outline" className="font-black italic text-[10px] border-none bg-secondary/10 text-secondary tracking-widest">
                                {tournament?.format?.replace('_', ' ')}
                            </Badge>

                            <span className="text-[10px] font-black tracking-widest text-muted-foreground italic px-2 border-l border-foreground/10">
                                {initialTeams.length} {tTournament("teams")}
                            </span>

                            <Badge className={cn(
                                "font-black italic border-none px-3 py-1 shadow-lg text-[10px] h-5 tracking-widest",
                                tournament?.status === 'active' && "bg-green-600 hover:bg-green-700 shadow-green-900/20",
                                tournament?.status === 'completed' && "bg-gray-500 hover:bg-gray-600 shadow-gray-900/20",
                                (!tournament?.status || tournament?.status === 'draft') && "bg-yellow-500 hover:bg-yellow-600 text-black shadow-yellow-900/10"
                            )}>
                                {tTournament(tournament?.status || 'draft')}
                            </Badge>

                            <Badge variant="secondary" className="text-[10px] px-1.5 py-0 h-5 border-none font-black italic tracking-tighter bg-foreground/5 text-muted-foreground/60">
                                {t("beta")}
                            </Badge>
                        </div>

                        {/* Title Section */}
                        <div className="flex flex-wrap items-center gap-2 md:gap-3">
                            <h1 className="text-3xl md:text-6xl font-black italic tracking-tighter leading-[0.85] text-foreground drop-shadow-2xl">
                                {tournament?.name}
                            </h1>
                        </div>
                    </div>

                    <div className="md:hidden shrink-0 pt-1 flex items-center gap-2 md:gap-3">
                        <ShareButton tournamentId={tournament.id} />
                    </div>
                </div>

                <div className="hidden md:flex items-center gap-2 md:gap-3 self-end md:self-start pt-2 md:pt-0">
                    <PrintButton />
                    <ShareButton tournamentId={tournament.id} />
                </div>
            </div>

            <div className="hidden md:block mb-6">
                <TournamentStats
                    matches={matches}
                    teams={initialTeams}
                    goals={goals}
                />
            </div>

            <Tabs value={currentTab} onValueChange={handleTabChange} className="w-full">
                <TabsList className="flex p-1 bg-muted/20 gap-1 border border-border h-auto w-full md:w-max print:hidden backdrop-blur-sm">
                    <TabsTrigger
                        value="overview"
                        className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-2 text-[10px] font-black italic transition-all border-none data-[state=active]:!bg-secondary data-[state=active]:!text-secondary-foreground data-[state=active]:shadow-[0_0_20px_rgba(0,196,154,0.4)] text-muted-foreground hover:text-secondary hover:bg-foreground/5"
                    >
                        <Trophy className="h-3.5 w-3.5" />
                        {t("overview")}
                    </TabsTrigger>
                    <TabsTrigger
                        value="matches"
                        className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-2 text-[10px] font-black italic transition-all border-none data-[state=active]:!bg-secondary data-[state=active]:!text-secondary-foreground data-[state=active]:shadow-[0_0_20px_rgba(0,196,154,0.4)] text-muted-foreground hover:text-secondary hover:bg-foreground/5"
                    >
                        <Calendar className="h-3.5 w-3.5" />
                        {t("matches")}
                    </TabsTrigger>
                </TabsList>

                <TabsContent value="overview" className="space-y-4 md:space-y-6">
                    <div className="grid grid-cols-1 gap-4 md:gap-6">
                        {(tournament.format === 'league' || tournament.format === 'league_ha') && (
                            <div className="space-y-4 md:space-y-6">
                                <div className="flex flex-col gap-1">
                                    <h2 className="text-xl font-black italic tracking-tighter text-foreground flex items-center gap-2 md:gap-3">
                                        <Trophy className="h-5 w-5 text-secondary" />
                                        {t("league_table")}
                                    </h2>
                                    <p className="text-[10px] font-bold text-muted-foreground/60">{t("league_table_desc")}</p>
                                </div>
                                <Card className="bg-background border relative overflow-hidden group hover:bg-muted/2 transition-colors shadow-xl shadow-black/20">
                                    <div className="absolute top-0 left-0 z-30 w-1 h-full bg-secondary" />
                                    <CardContent className="p-0 z-0">
                                        <StandingsTable standings={standings} />
                                    </CardContent>
                                </Card>
                            </div>
                        )}

                        {tournament.format === 'group_knockout' && (
                            <div className="space-y-4 md:space-y-6">
                                <div className="flex flex-col gap-1">
                                    <h2 className="text-xl font-black italic tracking-tighter text-foreground flex items-center gap-2 md:gap-3">
                                        <Trophy className="h-5 w-5 text-secondary" />
                                        {t("group_standings")}
                                    </h2>
                                    <p className="text-[10px] font-bold text-muted-foreground/60">{t("group_standings_desc")}</p>
                                </div>
                                <Card className="bg-background border relative overflow-hidden group transition-colors shadow-xl shadow-black/20">
                                    <div className="absolute top-0 left-0 z-30 w-1 h-full bg-secondary" />
                                    <CardContent className="p-0 z-0">
                                        <GroupStandings teams={initialTeams} matches={matches} isPublic={true} />
                                    </CardContent>
                                </Card>
                            </div>
                        )}

                        {(tournament.format === 'knockout' || tournament.format === 'group_knockout') && (
                            <div className="space-y-4 md:space-y-6">
                                <div className="flex flex-col gap-1">
                                    <h2 className="text-xl font-black italic tracking-tighter text-foreground flex items-center gap-2 md:gap-3">
                                        <GitBranch className="h-5 w-5 text-secondary" />
                                        {t("bracket")}
                                    </h2>
                                    <p className="text-[10px] font-bold text-muted-foreground/60">{t("bracket_desc")}</p>
                                </div>
                                <div className="relative z-10 overflow-x-auto pb-4">
                                    <TournamentBracket matches={matches} isPublic={true} />
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 pt-8 border-t border-foreground/5">
                        <div className="space-y-4 md:space-y-6">
                            <div className="flex flex-col gap-1">
                                <h2 className="text-xl font-black italic tracking-tighter text-foreground flex items-center gap-2 md:gap-3">
                                    <Award className="h-5 w-5 text-secondary" />
                                    {t("top_scorers")}
                                </h2>
                                <p className="text-[10px] font-bold text-muted-foreground/60">{t("top_scorers_desc")}</p>
                            </div>
                            <Card className="bg-background border relative overflow-hidden group hover:bg-muted/2 transition-colors shadow-xl shadow-black/20">
                                <div className="absolute top-0 left-0 z-30 w-1 h-full bg-secondary" />
                                <CardContent className="p-0 z-0">
                                    <TopScorersTable goals={goals} teams={initialTeams} />
                                </CardContent>
                            </Card>
                        </div>

                        <div className="space-y-12">
                            <div className="space-y-4 md:space-y-6">
                                <div className="flex flex-col gap-1">
                                    <h2 className="text-xl font-black italic tracking-tighter text-foreground flex items-center gap-2 md:gap-3">
                                        <Users className="h-5 w-5 text-secondary" />
                                        {t("player_stats")}
                                    </h2>
                                    <p className="text-[10px] font-bold text-muted-foreground/60">{t("player_stats_desc")}</p>
                                </div>
                                <Card className="bg-background border relative overflow-hidden group hover:bg-muted/2 transition-colors shadow-xl shadow-black/20">
                                    <div className="absolute top-0 left-0 z-30 w-1 h-full bg-secondary" />
                                    <CardContent className="p-0 z-0">
                                        <div className="overflow-x-auto">
                                            <PlayerStatsTable stats={playerStats} />
                                        </div>
                                    </CardContent>
                                </Card>
                            </div>

                            {bannedPlayers.length > 0 && (
                                <BannedPlayersCard bannedPlayers={bannedPlayers} />
                            )}
                        </div>
                    </div>
                </TabsContent>

                <TabsContent value="matches">
                    <div className="space-y-4 md:space-y-6">
                        <div className="flex flex-col gap-1">
                            <h2 className="text-xl font-black italic tracking-tighter text-foreground flex items-center gap-2 md:gap-3">
                                <Calendar className="h-5 w-5 text-secondary" />
                                {t("fixtures_results")}
                            </h2>
                            <p className="text-[10px] font-bold text-muted-foreground/60">{t("fixtures_results_desc")}</p>
                        </div>
                        <PublicMatchList matches={matches} tournamentId={tournament.id} events={events} />
                    </div>
                </TabsContent>
            </Tabs>
        </main>
    );
}

"use client";

import { useActionState, useTransition, useEffect, useState } from "react";
import { updateTournament } from "@/actions/organizer/tournaments/general";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Switch } from "@/components/ui/switch";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useTranslations } from "next-intl";
import { useToast } from "@/hooks/use-toast";
import { Check, AlertTriangle, ClipboardEdit, Loader2 } from "lucide-react";
import { cn } from "@/lib/utils";
import { ActionResponse } from "@/types/index";

const initialState: ActionResponse = {
    success: false,
    error: undefined,
};

interface RegistrationSettingsCardProps {
    tournament: any;
    isPro: boolean;
    onUpgrade?: () => void;
}

export function RegistrationSettingsCard({ tournament, isPro, onUpgrade }: RegistrationSettingsCardProps) {
    const t = useTranslations("Settings");
    const tCommon = useTranslations("Common");
    const { toast } = useToast();
    const [isPending, startTransition] = useTransition();
    const [mounted, setMounted] = useState(false);

    const updateTournamentWithId = updateTournament.bind(null, tournament.id);
    const [state, formAction] = useActionState(updateTournamentWithId, initialState);

    useEffect(() => {
        const timer = setTimeout(() => setMounted(true), 0);
        return () => clearTimeout(timer);
    }, []);

    useEffect(() => {
        if (state.success) {
            toast({
                title: tCommon("success"),
                description: t("update_success_desc") || "Registration settings updated",
            });
        } else if (state.error) {
            toast({
                title: tCommon("error"),
                description: state.error,
                variant: "destructive",
            });
        }
    }, [state, tCommon, t, toast]);

    if (!mounted) return null;


    return (
        <div className="space-y-4 md:space-y-6">
            <div className="flex items-center justify-between">
                <div className="flex flex-col gap-1">
                    <h3 className="text-xl font-black italic tracking-tighter text-foreground flex items-center gap-2 md:gap-3">
                        <ClipboardEdit className="h-5 w-5 text-secondary" />
                        {t("registration_settings")}
                    </h3>
                    <p className="text-[10px] font-bold text-muted-foreground/60">{t("registration_settings_desc")}</p>
                </div>
                {!isPro && (
                    <Badge variant="secondary" className="bg-secondary text-secondary-foreground text-[10px] font-black px-3 py-1 tracking-widest">
                        {t("pro_badge")}
                    </Badge>
                )}
            </div>

            <div className="bg-background border relative overflow-hidden group hover:bg-muted/5 transition-colors p-4 md:p-6 shadow-sm">
                <div className="absolute top-0 left-0 w-1 h-full bg-muted group-hover:bg-secondary/40 transition-colors" />
                
                <div className="relative z-10 space-y-4 md:space-y-6">
                    {!isPro && (
                        <div className="p-4 bg-secondary/5 border border-secondary/20 text-[11px] text-secondary font-black tracking-wider flex items-center gap-3">
                            <AlertTriangle className="h-4 w-4" />
                            <span>
                                {t("upsell_pro_feature", { defaultValue: "Tournament registrations are a Pro feature." })} 
                                <button onClick={onUpgrade} className="underline ml-2 hover:text-foreground transition-colors">{t("upgrade_button")}</button>
                            </span>
                        </div>
                    )}

                    <form action={formAction} className={cn("flex flex-col gap-2 md:gap-3", !isPro && "opacity-40 grayscale pointer-events-none")}>
                        <input type="hidden" name="form_type" value="registration" />
                        <input type="hidden" name="name" value={tournament.name} />
                        <input type="hidden" name="status" value={tournament.status || "draft"} />
                        <input type="hidden" name="format" value={tournament.format || "league"} />
                        <input type="hidden" name="max_teams" value={tournament.max_teams || 8} />

                        <div className="flex items-center justify-between p-4 md:p-6 bg-foreground/5 border-none">
                            <div className="space-y-1">
                                <Label htmlFor="is_registration_open" className="text-sm md:text-lg font-black italic tracking-tight text-foreground">
                                    {t("allow_registration")}
                                </Label>
                                <p className="text-[10px] font-bold text-muted-foreground/60 tracking-wider">
                                    {t("allow_registration_desc")}
                                </p>
                            </div>
                            <Switch
                                id="is_registration_open"
                                name="is_registration_open"
                                value="true"
                                defaultChecked={tournament.is_registration_open}
                                disabled={!isPro}
                                className="data-[state=checked]:bg-secondary"
                            />
                        </div>

                        <div className="space-y-2 md:space-y-3">
                            <div className="space-y-1">
                                <Label htmlFor="registration_fee" className="text-[10px] font-black tracking-wider text-muted-foreground/60">{t("registration_fee")}</Label>
                                <Input
                                    type="number"
                                    id="registration_fee"
                                    name="registration_fee"
                                    defaultValue={tournament.registration_fee}
                                    placeholder="0.00"
                                    min="0"
                                    step="0.01"
                                    disabled={!isPro}
                                    className="h-12 bg-foreground/5 border-none focus-visible:ring-1 focus-visible:ring-primary/50 transition-all placeholder:text-muted-foreground/30 font-bold italic tracking-tighter"
                                />
                            </div>
                            <div className="space-y-1">
                                <Label htmlFor="bank_account_number" className="text-[10px] font-black tracking-wider text-muted-foreground/60">{t("promptpay_id")}</Label>
                                <Input
                                    type="text"
                                    id="bank_account_number"
                                    name="bank_account_number"
                                    defaultValue={tournament.bank_account_number}
                                    placeholder="08xxxxxxxx or ID Card"
                                    disabled={!isPro}
                                    className="h-12 bg-foreground/5 border-none focus-visible:ring-1 focus-visible:ring-primary/50 transition-all placeholder:text-muted-foreground/30 font-bold italic tracking-tighter"
                                />
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-2 md:gap-3">
                                <div className="space-y-1">
                                    <Label htmlFor="bank_name" className="text-[10px] font-black tracking-wider text-muted-foreground/60">{t("bank_name")}</Label>
                                    <Select name="bank_name" defaultValue={tournament.bank_name || "PromptPay"} disabled={!isPro}>
                                        <SelectTrigger id="bank_name" className="h-12 bg-foreground/5 border-none focus:ring-1 focus:ring-primary/50 transition-all font-bold italic tracking-tighter">
                                            <SelectValue placeholder={t("select_bank")} />
                                        </SelectTrigger>
                                        <SelectContent className="bg-neutral-950 border-foreground/10">
                                            <SelectItem value="PromptPay">PromptPay</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="space-y-1">
                                    <Label htmlFor="bank_account_name" className="text-[10px] font-black tracking-wider text-muted-foreground/60">{t("account_name")}</Label>
                                    <Input
                                        type="text"
                                        id="bank_account_name"
                                        name="bank_account_name"
                                        defaultValue={tournament.bank_account_name}
                                        placeholder={t("account_name")}
                                        disabled={!isPro}
                                        className="h-12 bg-foreground/5 border-none focus-visible:ring-1 focus-visible:ring-primary/50 transition-all placeholder:text-muted-foreground/30 font-bold italic tracking-tighter"
                                    />
                                </div>
                            </div>

                            <Button 
                                type="submit" 
                                disabled={!isPro || isPending}
                                className="w-full h-12 bg-secondary text-secondary-foreground font-black italic tracking-tighter hover:bg-secondary/90 transition-all relative group overflow-hidden"
                            >
                                <div className="absolute inset-0 bg-foreground/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300" />
                                <span className="relative z-10 flex items-center justify-center gap-2">
                                    {isPending ? <Loader2 className="h-4 w-4 animate-spin" /> : <Check className="h-4 w-4" />}
                                    {tCommon("save")}
                                </span>
                            </Button>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { Player, GlobalPlayer } from "@/types/index";
import { addPlayer, getPlayers, deletePlayer, updatePlayer } from "@/actions/organizer/tournaments/player";
import {  linkPlayerToGlobal, unlinkPlayerFromGlobal } from "@/actions/organizer/tournaments/global-player";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Table, TableRow } from "@/components/ui/table";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Loader2, UserPlus, Trash2, Users, Link2, Unlink, Search, Save, X, Eye, FileText, ArrowRight, MoreVertical, Edit2, Plus } from "lucide-react";
import { useTranslations, useLocale } from "next-intl";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { useToast } from "@/hooks/use-toast";
import { Badge } from "@/components/ui/badge";

interface RosterDialogProps {
    teamId: string;
    teamName: string;
    trigger?: React.ReactNode;
    readOnly?: boolean;
}

export function RosterDialog({ teamId, teamName, trigger, readOnly = false }: RosterDialogProps) {
    const t = useTranslations("Roster");
    const tCommon = useTranslations("Common");
    const { toast } = useToast();

    const [open, setOpen] = useState(false);
    const [players, setPlayers] = useState<Player[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const locale = useLocale();

    const formatDate = (dateStr: string | null | undefined) => {
        if (!dateStr || dateStr === "0000-00-00") return "";
        const date = new Date(dateStr);
        if (isNaN(date.getTime())) return "";

        return date.toLocaleDateString(locale === 'th' ? 'th-TH' : 'en-US', {
            day: '2-digit',
            month: '2-digit',
            year: 'numeric'
        });
    };

    // Form State
    const [newName, setNewName] = useState("");
    const [newNumber, setNewNumber] = useState("");
    const [newPosition, setNewPosition] = useState("");
    const [newBirthDate, setNewBirthDate] = useState("");

    // Global Player Search State
    const [linkingPlayerId, setLinkingPlayerId] = useState<string | null>(null);
    const [playerToDelete, setPlayerToDelete] = useState<string | null>(null);
    const [searchQuery, setSearchQuery] = useState("");
    const [searchResults, setSearchResults] = useState<GlobalPlayer[]>([]);
    const [isSearching, setIsSearching] = useState(false);

    // Edit State
    const [editingPlayerId, setEditingPlayerId] = useState<string | null>(null);
    const [editName, setEditName] = useState<string>("");
    const [editNumber, setEditNumber] = useState<string>("");
    const [editPosition, setEditPosition] = useState<string>("");
    const [editBirthDate, setEditBirthDate] = useState<string>("");

    const fetchPlayers = useCallback(async () => {
        setIsLoading(true);
        const result = await getPlayers(teamId);
        if (result.success && result.data) {
            setPlayers(result.data);
        } else {
            toast({
                title: tCommon("error"),
                description: t("no_players"),
                variant: "destructive",
            });
        }
        setIsLoading(false);
    }, [teamId, tCommon, t, toast]);

    useEffect(() => {
        if (open) {
            fetchPlayers();
        }
    }, [open, fetchPlayers]);

    // Search for global players (now allows empty query to fetch initial list)
    const handleSearch = useCallback(async (query: string) => {
        setSearchQuery(query);
        setIsSearching(true);
        const { searchGlobalPlayers } = await import("@/actions/organizer/tournaments/global-player");
        const result = await searchGlobalPlayers(query);
        if (result.success && result.data) {
            setSearchResults(result.data);
        } else {
            setSearchResults([]);
        }
        setIsSearching(false);
    }, []);

    const handleAddPlayer = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!newName.trim()) return;

        setIsSaving(true);
        const formData = new FormData();
        formData.append("name", newName);
        formData.append("number", newNumber);
        formData.append("position", newPosition);
        formData.append("birthDate", newBirthDate);

        const result = await addPlayer(teamId, null, formData);

        setIsSaving(false);
        if (result.success) {
            toast({
                title: tCommon("success"),
                description: t("added_success"),
            });
            setNewName("");
            setNewNumber("");
            setNewPosition("");
            setNewBirthDate("");
            fetchPlayers();
        } else {
            toast({
                title: tCommon("error"),
                description: result.error || tCommon("error"),
                variant: "destructive",
            });
        }
    };

    const confirmDeletePlayer = async () => {
        if (!playerToDelete) return;

        const result = await deletePlayer(playerToDelete);
        setPlayerToDelete(null);
        if (result.success) {
            toast({
                title: tCommon("success"),
                description: t("deleted_success"),
            });
            fetchPlayers();
        } else {
            toast({
                title: tCommon("error"),
                description: result.error || tCommon("error"),
                variant: "destructive",
            });
        }
    };

    const handleUpdatePlayer = async (playerId: string) => {
        setIsSaving(true);
        const result = await updatePlayer(playerId, {
            name: !players.find(p => p.id === playerId)?.global_player_id ? (editName || undefined) : undefined,
            number: editNumber ? parseInt(editNumber) : null,
            position: editPosition || null,
            birth_date: editBirthDate || null,
        });
        setIsSaving(false);

        if (result.success) {
            toast({ title: tCommon("success"), description: t("updated_success") || "Player updated" });
            setEditingPlayerId(null);
            fetchPlayers();
        } else {
            toast({ title: tCommon("error"), description: result.error, variant: "destructive" });
        }
    };

    const handleLinkPlayer = async (playerId: string, globalPlayer: GlobalPlayer) => {
        const result = await linkPlayerToGlobal(playerId, globalPlayer.id);
        if (result.success) {
            toast({ title: tCommon("success"), description: "Player linked successfully" });
            setLinkingPlayerId(null);
            setSearchQuery("");
            setSearchResults([]);
            fetchPlayers();
        } else {
            toast({ title: tCommon("error"), description: result.error, variant: "destructive" });
        }
    };

    const handleUnlinkPlayer = async (playerId: string) => {
        const result = await unlinkPlayerFromGlobal(playerId);
        if (result.success) {
            toast({ title: tCommon("success"), description: "Player unlinked" });
            fetchPlayers();
        } else {
            toast({ title: tCommon("error"), description: result.error, variant: "destructive" });
        }
    };

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                {trigger || (
                    <Button variant="outline" size="sm" className="h-8 gap-2 hover:bg-muted/10">
                        {readOnly ? (
                            <Eye className="h-4 w-4 text-muted-foreground" />
                        ) : (
                            <Users className="h-4 w-4 text-muted-foreground" />
                        )}
                        <span className="hidden sm:inline font-bold italic tracking-tighter text-xs">
                            {readOnly ? t("view_squad") : t("manage_squad")}
                        </span>
                    </Button>
                )}
            </DialogTrigger>
            <DialogContent className="max-w-2xl max-h-[85vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle>{t("title")} - {teamName}</DialogTitle>
                </DialogHeader>

                <div className="space-y-6">
                    {/* Add Player Form */}
                    {!readOnly && (
                        <div className="bg-card border border-border/40 relative overflow-hidden group">
                            <div className="absolute left-0 w-1 h-full bg-secondary transition-all" />
                            <div className="p-4">
                                <div className="flex items-center justify-between mb-5">
                                    <div className="space-y-1 block w-full">
                                        <div className="flex items-center w-full">
                                            <h3 className="text-lg font-black italic tracking-tighter text-foreground flex items-center gap-2">
                                                <UserPlus className="h-5 w-5 text-secondary" />
                                                {t("add_player")}
                                            </h3>
                                            <div className="h-px flex-1 bg-gradient-to-r from-secondary/20 to-transparent ml-4 hidden sm:block" />
                                        </div>
                                    </div>
                                </div>

                                <form onSubmit={handleAddPlayer} className="grid grid-cols-1 sm:grid-cols-12 gap-4 items-start">
                                    <div className="sm:col-span-5 space-y-2 relative">
                                        <label className="text-[10px] font-bold tracking-wider text-muted-foreground ml-1">{t("player_name")} *</label>
                                        <Input
                                            value={newName}
                                            onChange={e => setNewName(e.target.value)}
                                            placeholder={t("player_name")}
                                            required
                                            className="h-10 bg-background/50 border-input/50 focus-visible:ring-secondary/20 focus-visible:border-secondary transition-all"
                                        />
                                    </div>
                                    <div className="sm:col-span-2 space-y-2">
                                        <label className="text-[10px] font-bold tracking-wider text-muted-foreground ml-1">{t("birth_date") || "Birth Date"}</label>
                                        <Input
                                            value={newBirthDate}
                                            onChange={e => setNewBirthDate(e.target.value)}
                                            type="date"
                                            lang={locale === 'th' ? 'th-TH' : 'en-US'}
                                            className="h-10 bg-background/50 border-input/50 focus-visible:ring-secondary/20 focus-visible:border-secondary transition-all"
                                        />
                                    </div>
                                    <div className="sm:col-span-2 space-y-2">
                                        <label className="text-[10px] font-bold tracking-wider text-muted-foreground ml-1">{t("number")}</label>
                                        <Input
                                            value={newNumber}
                                            onChange={e => setNewNumber(e.target.value)}
                                            placeholder="10"
                                            type="number"
                                            className="h-10 bg-background/50 border-input/50 focus-visible:ring-secondary/20 focus-visible:border-secondary transition-all text-center font-bold"
                                        />
                                    </div>
                                    <div className="sm:col-span-2 space-y-2">
                                        <label className="text-[10px] font-bold tracking-wider text-muted-foreground ml-1">{t("position")}</label>
                                        <Select value={newPosition} onValueChange={setNewPosition}>
                                            <SelectTrigger className="h-10 bg-background/50 border-input/50 focus-visible:ring-secondary/20 focus-visible:border-secondary transition-all">
                                                <SelectValue placeholder="POS" />
                                            </SelectTrigger>
                                            <SelectContent className="">
                                                <SelectItem value="GK" className="cursor-pointer">GK {t("goalkeeper")}</SelectItem>
                                                <SelectItem value="DF" className="cursor-pointer">DF {t("defender")}</SelectItem>
                                                <SelectItem value="MF" className="cursor-pointer">MF {t("midfielder")}</SelectItem>
                                                <SelectItem value="FW" className="cursor-pointer">FW {t("forward")}</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="sm:col-span-2 space-y-2">
                                        <label className="text-[10px] font-bold tracking-wider text-transparent select-none hidden sm:block">Action</label>
                                        <Button 
                                            type="submit" 
                                            className="w-full h-10 font-black italic tracking-wider text-xs transition-all bg-secondary text-secondary-foreground hover:bg-secondary/90 shadow-[0_0_15px_rgba(0,255,157,0.15)]" 
                                            disabled={isSaving || !newName.trim()}
                                        >
                                            {isSaving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Plus className="h-3.5 w-3.5 mr-1" />}
                                            {t("add")}
                                        </Button>
                                    </div>
                                </form>
                            </div>
                        </div>
                    )}

                    {/* Player List */}
                    <div>
                        {isLoading ? (
                            <div className="flex justify-center py-8">
                                <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
                            </div>
                        ) : players.length === 0 ? (
                            <div className="flex flex-col items-center justify-center py-12 text-center border border-dashed bg-muted/10">
                                <div className="h-12 w-12 bg-muted/20 flex items-center justify-center mb-4">
                                    <Users className="h-6 w-6 text-muted-foreground" />
                                </div>
                                <h3 className="text-sm font-medium text-muted-foreground">{t("no_players_desc")}</h3>
                                <p className="text-sm text-muted-foreground mt-1 max-w-sm">
                                    Please add players to this team.
                                </p>
                            </div>
                        ) : (
                            <div className="grid gap-4">
                                {players.map((player) => (
                                    <div key={player.id} className="group bg-card border border-border/40 relative overflow-hidden transition-all hover:border-secondary/30 hover:shadow-[0_0_20px_rgba(0,0,0,0.2)]">
                                        <div className="absolute left-0 top-0 w-1 h-full bg-secondary opacity-80 group-hover:opacity-100 transition-opacity" />

                                        <div className="p-4 flex flex-col md:flex-row md:items-center gap-6">
                                            {/* Player Number & Avatar */}
                                            <div className="flex items-center gap-4 shrink-0">
                                                <div className="w-12 h-12 bg-muted/20 border border-border/40 flex items-center justify-center relative">
                                                    {editingPlayerId === player.id ? (
                                                        <Input
                                                            value={editNumber}
                                                            onChange={e => setEditNumber(e.target.value)}
                                                            className="h-full w-full border-none bg-secondary/10 text-center font-mono text-xl font-black focus-visible:ring-0 p-0 shadow-none"
                                                            type="number"
                                                            autoFocus
                                                        />
                                                    ) : (
                                                        <span className="font-mono text-2xl font-black italic tracking-tighter text-secondary">
                                                            {player.number?.toString().padStart(2, '0') || "??"}
                                                        </span>
                                                    )}
                                                </div>

                                                <div className="h-12 w-12 border border-border/40 overflow-hidden bg-muted/10 relative">
                                                    {player.photo_url || player.global_player?.photo_url ? (
                                                        // eslint-disable-next-line @next/next/no-img-element
                                                        <img src={player.photo_url || player.global_player?.photo_url || ""} alt={player.name} className="h-full w-full object-cover" />
                                                    ) : (
                                                        <div className="h-full w-full flex items-center justify-center opacity-20">
                                                            <Users className="h-6 w-6" />
                                                        </div>
                                                    )}
                                                </div>
                                            </div>

                                            {/* Player Name & Connection */}
                                             <div className="flex-1 min-w-0 pr-12 md:pr-0">
                                                <div className="flex items-center flex-wrap gap-3 mb-1">
                                                    {(editingPlayerId === player.id && !player.global_player_id) ? (
                                                        <Input
                                                            value={editName}
                                                            onChange={e => setEditName(e.target.value)}
                                                            className="h-10 flex-1 min-w-[200px] border-t-0 border-x-0 border-border/40 bg-secondary/10 text-xl font-black italic tracking-tighter text-secondary focus-visible:ring-0"
                                                            placeholder={t("player_name")}
                                                            autoFocus
                                                        />
                                                    ) : (
                                                        <h4 className="text-xl font-black italic tracking-tighter text-foreground leading-none group-hover:text-secondary transition-colors">
                                                            {player.name}
                                                        </h4>
                                                    )}

                                                    {player.global_player_id ? (
                                                        <Badge variant="secondary" className="bg-secondary/10 text-secondary border-none text-[9px] font-black tracking-widest px-2 py-0.5">
                                                            <Link2 className="h-2.5 w-2.5 mr-1" />
                                                            {t("verified") || "VERIFIED"}
                                                        </Badge>
                                                    ) : (
                                                        <Badge variant="outline" className="border-muted-foreground/20 text-muted-foreground/40 text-[9px] font-black tracking-widest px-2 py-0.5">
                                                            {t("local_only") || "LOCAL ONLY"}
                                                        </Badge>
                                                    )}

                                                    <div className="flex items-center gap-2">
                                                        {editingPlayerId === player.id ? (
                                                            <Select value={editPosition} onValueChange={setEditPosition}>
                                                                <SelectTrigger className="h-7 w-20 border-t-0 border-x-0 border-border/40 bg-muted/20 text-[9px] font-black tracking-widest p-1 focus:ring-0 [&_svg]:hidden">
                                                                    <SelectValue placeholder="POS" />
                                                                </SelectTrigger>
                                                                <SelectContent className="border-border">
                                                                    <SelectItem value="FW" className="text-[9px] font-black tracking-widest">{t("forward") || "FW"}</SelectItem>
                                                                </SelectContent>
                                                            </Select>
                                                        ) : (
                                                            <Badge className="bg-muted border-none text-muted-foreground text-[9px] font-black tracking-widest px-2 py-0.5">
                                                                {player.position || "N/A"}
                                                            </Badge>
                                                        )}

                                                        {(editingPlayerId === player.id && !player.global_player_id) ? (
                                                            <Input
                                                                value={editBirthDate}
                                                                onChange={e => setEditBirthDate(e.target.value)}
                                                                type="date"
                                                                lang={locale === 'th' ? 'th-TH' : 'en-US'}
                                                                className="h-7 w-28 border-t-0 border-x-0 border-border/40 bg-muted/10 text-[9px] font-black p-1 focus-visible:ring-0 shadow-none"
                                                            />
                                                        ) : (
                                                            player.birth_date && (
                                                                <span className="text-[10px] font-bold tracking-widest text-muted-foreground/40 font-mono">
                                                                    {formatDate(player.birth_date)}
                                                                </span>
                                                            )
                                                        )}
                                                    </div>
                                                </div>

                                                <div className="flex items-center gap-4 mt-3">
                                                    {!player.global_player_id && !readOnly && (
                                                        <Popover
                                                            open={linkingPlayerId === player.id}
                                                            onOpenChange={(isOpen) => {
                                                                setLinkingPlayerId(isOpen ? player.id : null);
                                                                if (isOpen) {
                                                                    setSearchQuery("");
                                                                    handleSearch("");
                                                                } else {
                                                                    setSearchQuery("");
                                                                    setSearchResults([]);
                                                                }
                                                            }}
                                                        >
                                                            <PopoverTrigger asChild>
                                                                <Button variant="link" size="sm" className="p-0 h-auto text-[10px] font-black tracking-widest text-secondary hover:text-secondary/80 flex items-center gap-2">
                                                                    <Link2 className="h-3.5 w-3.5" />
                                                                    {tCommon("search")} Global ID
                                                                </Button>
                                                            </PopoverTrigger>
                                                            <PopoverContent className="w-80 p-0 border-border bg-card shadow-2xl" align="start">
                                                                <div className="p-0 border-b border-border/40">
                                                                    <div className="relative group/search">
                                                                        <div className="relative">
                                                                            <Search className="absolute left-5 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground/30 group-focus-within/search:text-secondary group-focus-within/search:scale-110 transition-all duration-300 z-10" />
                                                                            <Input
                                                                                placeholder="Start typing..."
                                                                                value={searchQuery}
                                                                                onChange={(e) => handleSearch(e.target.value)}
                                                                                className="pl-14 h-16 text-xs bg-muted/5 border-none group-focus-within/search:bg-muted/10 transition-all duration-500 font-black italic tracking-widest placeholder:text-muted-foreground/20 focus-visible:ring-0 shadow-none relative z-10"
                                                                                autoFocus
                                                                            />
                                                                            <div className="absolute bottom-0 left-0 w-0 h-[2px] bg-secondary group-focus-within/search:w-full transition-all duration-700 z-20" />
                                                                        </div>
                                                                    </div>
                                                                </div>
                                                                <div className="max-h-[300px] overflow-y-auto custom-scrollbar">
                                                                    {isSearching ? (
                                                                        <div className="flex flex-col items-center justify-center py-12 gap-3">
                                                                            <Loader2 className="h-6 w-6 animate-spin text-secondary" />
                                                                            <span className="text-[9px] font-black tracking-widest text-muted-foreground/40">Scanning Database</span>
                                                                        </div>
                                                                    ) : searchResults.length > 0 ? (
                                                                        <div className="py-2">
                                                                            {searchResults.map((gp) => (
                                                                                <button
                                                                                    key={gp.id}
                                                                                    className="w-full text-left px-5 py-3 hover:bg-secondary/10 group/item flex items-center justify-between transition-colors border-b border-border/20 last:border-0"
                                                                                    onClick={() => handleLinkPlayer(player.id, gp)}
                                                                                >
                                                                                    <div className="flex flex-col">
                                                                                        <span className="font-black italic text-xs tracking-tight group-hover/item:text-secondary">{gp.name}</span>
                                                                                        {gp.date_of_birth && (
                                                                                            <span className="text-[9px] font-mono font-bold text-muted-foreground/60 mt-0.5">
                                                                                                {formatDate(gp.date_of_birth)}
                                                                                            </span>
                                                                                        )}
                                                                                    </div>
                                                                                    <ArrowRight className="h-3.5 w-3.5 text-muted-foreground/20 opacity-0 group-hover/item:opacity-100 group-hover/item:text-secondary group-hover/item:translate-x-1 transition-all" />
                                                                                </button>
                                                                            ))}
                                                                        </div>
                                                                    ) : (
                                                                        <div className="p-8 text-center space-y-4">
                                                                            <div className="h-10 w-10 bg-muted/20 border border-border/40 flex items-center justify-center mx-auto">
                                                                                {searchQuery ? <FileText className="h-5 w-5 text-muted-foreground/20" /> : <Search className="h-5 w-5 text-muted-foreground/20" />}
                                                                            </div>
                                                                            <p className="text-[10px] font-bold tracking-widest text-muted-foreground/40">
                                                                                {tCommon("no_results") || "No records found"}
                                                                            </p>
                                                                            {searchQuery && (
                                                                                <Button
                                                                                    size="sm"
                                                                                    variant="outline"
                                                                                    className="w-full h-10 text-[9px] font-black tracking-widest border-2 hover:bg-secondary hover:text-black hover:border-secondary transition-all"
                                                                                    onClick={async () => {
                                                                                        const { createGlobalPlayer } = await import("@/actions/organizer/tournaments/global-player");
                                                                                        const res = await createGlobalPlayer(searchQuery, null, player.birth_date);
                                                                                        if (res.success && res.data) {
                                                                                            await handleLinkPlayer(player.id, res.data);
                                                                                        } else {
                                                                                            toast({ title: tCommon("error"), description: res.error, variant: "destructive" });
                                                                                        }
                                                                                    }}
                                                                                >
                                                                                    Create & Sync Global ID
                                                                                </Button>
                                                                            )}
                                                                        </div>
                                                                    )}
                                                                </div>
                                                                <div className="p-4 border-t border-border/40 bg-muted/5">
                                                                    {!searchQuery && (
                                                                        <Button
                                                                            size="sm"
                                                                            variant="ghost"
                                                                            className="w-full h-10 text-[9px] font-black tracking-widest justify-start px-2 hover:text-secondary transition-colors"
                                                                            onClick={async () => {
                                                                                const { createGlobalPlayer } = await import("@/actions/organizer/tournaments/global-player");
                                                                                const res = await createGlobalPlayer(player.name, null, player.birth_date);
                                                                                if (res.success && res.data) {
                                                                                    await handleLinkPlayer(player.id, res.data);
                                                                                } else {
                                                                                    toast({ title: tCommon("error"), description: res.error, variant: "destructive" });
                                                                                }
                                                                            }}
                                                                        >
                                                                            <UserPlus className="h-4 w-4 mr-3 opacity-40" />
                                                                            Create Global ID
                                                                        </Button>
                                                                    )}
                                                                </div>
                                                            </PopoverContent>
                                                        </Popover>
                                                    )}

                                                    {player.global_player_id && !readOnly && (
                                                        <Button
                                                            variant="link"
                                                            size="sm"
                                                            className="p-0 h-auto text-[10px] font-black tracking-widest text-red-500/60 hover:text-red-500 flex items-center gap-2"
                                                            onClick={() => handleUnlinkPlayer(player.id)}
                                                        >
                                                            <Unlink className="h-3.5 w-3.5" />
                                                            Unlink Identity
                                                        </Button>
                                                    )}

                                                    {player.global_player_id && (
                                                        <div className="flex items-center gap-1.5 opacity-40 group-hover:opacity-100 transition-opacity">
                                                            <div className="h-1.5 w-1.5 rounded-full bg-secondary" />
                                                            <span className="text-[9px] font-black tracking-[0.2em] text-foreground">Cloud Sync Active</span>
                                                        </div>
                                                    )}
                                                </div>
                                            </div>

                                            {/* Actions */}
                                            {!readOnly && (
                                                <div className="md:static absolute top-4 right-4 flex items-center justify-end gap-3 md:border-t-0 md:border-l border-border/20 md:pt-0 md:pl-6 shrink-0">
                                                    {editingPlayerId === player.id ? (
                                                        <div className="flex gap-2">
                                                            <Button
                                                                variant="default"
                                                                size="icon"
                                                                className="h-10 w-10 bg-secondary text-black hover:bg-secondary/90 shadow-[0_0_15px_rgba(0,255,157,0.2)]"
                                                                onClick={() => handleUpdatePlayer(player.id)}
                                                                disabled={isSaving}
                                                            >
                                                                {isSaving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-5 w-5" />}
                                                            </Button>
                                                            <Button
                                                                variant="outline"
                                                                size="icon"
                                                                className="h-10 w-10 border-2"
                                                                onClick={() => setEditingPlayerId(null)}
                                                                disabled={isSaving}
                                                            >
                                                                <X className="h-5 w-5" />
                                                            </Button>
                                                        </div>
                                                    ) : (
                                                        <DropdownMenu>
                                                            <DropdownMenuTrigger asChild>
                                                                <Button
                                                                    variant="ghost"
                                                                    size="icon"
                                                                    className="h-10 w-10 text-muted-foreground hover:text-secondary hover:bg-muted/10 transition-all"
                                                                >
                                                                    <MoreVertical className="h-5 w-5" />
                                                                </Button>
                                                            </DropdownMenuTrigger>
